lag == 2: num = len('Python-') new_name = name[num:] # 打印新文件名，测试程序正确性 print(new_name) # 重命名 os.rename(dir_name+name, dir_name+new_name) 面向对象基础理解面向对象面向对象是一种抽象化的编程思想，很多编程语言中都有的一种思想。 例如：洗衣服思考：几种途径可以完成洗衣服？答： 手洗 和 机洗。手洗：找盆 - 放水 - 加洗衣粉 - 浸泡 - 搓洗 - 拧干水 - 倒水 - 漂洗N次 - 拧干 - 晾晒。机洗：打开洗衣机 - 放衣服 - 加洗衣粉 - 按下开始按钮 - 晾晒。思考：对比两种洗衣服途径，同学们发现了什么？答：机洗更简单思考：机洗，只需要找到一台洗衣机，加入简单操作就可以完成洗衣服的工作，而不需要关心洗衣机内部发生了什么事情。 总结：==面向对象就是将编程当成是一个事物，对外界来说，事物是直接使用的，不用去管他内部的情况。而编程就是设置事物能够做什么事。== 类和对象 思考：洗衣机洗衣服描述过程中，洗衣机其实就是一个事物，即对象，洗衣机对象哪来的呢？答：洗衣机是由工厂工人制作出来。思考：工厂工人怎么制作出的洗衣机？答：工人根据设计师设计的功能图纸制作洗衣机。总结：图纸 → 洗衣机 → 洗衣服。在面向对象编程过程中，有两个重要组成部分：==类== 和 ==对象==。==类和对象的关系：用类去创建一个对象。== 理解类和对象类类是对一系列具有相同==特征==和==行为==的事物的统称，是一个==抽象的概念==，不是真实存在的事物。 特征即是属性 行为即是方法类比如是制造洗衣机时要用到的图纸，也就是说==类是用来创建对象==。对象对象是类创建出来的真实存在的事物，例如：洗衣机。 注意：开发中，先有类，再有对象。 面向对象实现方法定义类Python2中类分为：经典类 和 新式类123class 类名(): 代码 ...... 注意：类名要满足标识符命名规则，同时遵循==大驼峰命名习惯==。 123class Washer(): def wash(self): print('我会洗衣服') 拓展：经典类 不由任意内置类型派生出的类，称之为经典类 123class 类名: 代码 ...... 创建对象:对象又名实例。1对象名 = 类名() 123456# 创建对象haier1 = Washer()# &lt;__main__.Washer object at 0x0000018B7B224240&gt;print(haier1)# haier对象调用实例方法haier1.wash() 注意：创建对象的过程也叫实例化对象。 self:self指的是调用该函数的对象。1234567891011121314151617# 1. 定义类class Washer(): def wash(self): print('我会洗衣服') # &lt;__main__.Washer object at 0x0000024BA2B34240&gt; print(self)# 2. 创建对象haier1 = Washer()# &lt;__main__.Washer object at 0x0000018B7B224240&gt;print(haier1)# haier1对象调用实例方法haier1.wash()haier2 = Washer()# &lt;__main__.Washer object at 0x0000022005857EF0&gt;print(haier2) 注意：打印对象和self得到的结果是一致的，都是当前对象的内存中存储地址。 添加和获取对象属性属性即是特征，比如：洗衣机的宽度、高度、重量…对象属性既可以在类外面添加和获取，也能在类里面添加和获取。 类外面添加对象属性1对象名.属性名 = 值 12haier1.width = 500haier1.height = 800 类外面获取对象属性1对象名.属性名 12print(f'haier1洗衣机的宽度是{haier1.width}')print(f'haier1洗衣机的高度是{haier1.height}') 类里面获取对象属性1self.属性名 体验1234567891011121314# 定义类class Washer(): def print_info(self): # 类里面获取实例属性 print(f'haier1洗衣机的宽度是{self.width}') print(f'haier1洗衣机的高度是{self.height}')# 创建对象haier1 = Washer()# 添加实例属性haier1.width = 500haier1.height = 800haier1.print_info()#haier1洗衣机的宽度是{500}#haier1洗衣机的高度是{800} 魔法方法 在Python中，__xx__()的函数叫做魔法方法，指的是具有特殊功能的函数。 __init__()思考：洗衣机的宽度高度是与生俱来的属性，可不可以在生产过程中就赋予这些属性呢？答：理应如此。==__init__()方法的作用：初始化对象。== 12345678910111213class Washer(): # 定义初始化功能的函数 def __init__(self): # 添加实例属性 self.width = 500 self.height = 800 def print_info(self): # 类里面调用实例属性 print(f'洗衣机的宽度是{self.width}, 高度是{self.height}')haier1 = Washer()haier1.print_info() 注意： __init__()方法，在创建一个对象时默认被调用，不需要手动调用 __init__(self)中的self参数，不需要开发者传递，python解释器会自动把当前的对象引用传递过去。 带参数的__init__()思考：一个类可以创建多个对象，如何对不同的对象设置不同的初始化属性呢？答：传参数。 123456789101112class Washer(): def __init__(self, width, height): self.width = width self.height = height def print_info(self): print(f'洗衣机的宽度是{self.width}') print(f'洗衣机的高度是{self.height}')haier1 = Washer(10, 20)haier1.print_info()haier2 = Washer(30, 40)haier2.print_info() __str__()当使用print输出对象的时候，默认打印对象的内存地址。如果类定义了__str__方法，那么就会打印从在这个方法中 return 的数据。 123456789class Washer(): def __init__(self, width, height): self.width = width self.height = height def __str__(self): return '这是海尔洗衣机的说明书'haier1 = Washer(10, 20)# 这是海尔洗衣机的说明书print(haier1) __del__()当删除对象时，python解释器也会默认调用__del__()方法。 123456789class Washer(): def __init__(self, width, height): self.width = width self.height = height def __del__(self): print(f'{self}对象已经被删除')haier1 = Washer(10, 20)# &lt;__main__.Washer object at 0x0000026118223278&gt;对象已经被删除del haier1 综合应用烤地瓜需求主线： 被烤的时间和对应的地瓜状态：0-3分钟：生的3-5分钟：半生不熟5-8分钟：熟的超过8分钟：烤糊了 添加的调料：用户可以按自己的意愿添加调料步骤分析需求涉及一个事物： 地瓜，故案例涉及一个类：地瓜类。定义类 地瓜的属性 被烤的时间 地瓜的状态 添加的调料 地瓜的方法 被烤 用户根据意愿设定每次烤地瓜的时间 判断地瓜被烤的总时间是在哪个区间，修改地瓜状态 添加调料 用户根据意愿设定添加的调料 将用户添加的调料存储 显示对象信息5.1.2.2 创建对象，调用相关实例方法代码实现 地瓜属性 定义地瓜初始化属性，后期根据程序推进更新实例属性12345678class SweetPotato(): def __init__(self): # 被烤的时间 self.cook_time = 0 # 地瓜的状态 self.cook_static = '生的' # 调料列表 self.condiments = [] 定义烤地瓜方法12345678910111213class SweetPotato(): ...... def cook(self, time): &quot;&quot;&quot;烤地瓜的方法&quot;&quot;&quot; self.cook_time += time if 0 &lt;= self.cook_time &lt; 3: self.cook_static = '生的' elif 3 &lt;= self.cook_time &lt; 5: self.cook_static = '半生不熟' elif 5 &lt;= self.cook_time &lt; 8: self.cook_static = '熟了' elif self.cook_time &gt;= 8: self.cook_static = '烤糊了' 书写str魔法方法，用于输出对象状态1234class SweetPotato(): ...... def __str__(self): return f'这个地瓜烤了{self.cook_time}分钟, 状态是{self.cook_static}' 创建对象，测试实例属性和实例方法1234digua1 = SweetPotato()print(digua1)digua1.cook(2)print(digua1) 定义添加调料方法，并调用该实例方法1234567891011121314151617181920212223class SweetPotato(): ...... def add_condiments(self, condiment): &quot;&quot;&quot;添加调料&quot;&quot;&quot; self.condiments.append(condiment) def __str__(self): return f'这个地瓜烤了{self.cook_time}分钟, 状态是{self.cook_static}, 添加的调料有{self.condiments}'digua1 = SweetPotato()print(digua1)digua1.cook(2)digua1.add_condiments('酱油')print(digua1)digua1.cook(2)digua1.add_condiments('辣椒面儿')print(digua1)digua1.cook(2)print(digua1)digua1.cook(2)print(digua1) 代码总览12345678910111213141516171819202122232425262728293031323334353637383940414243# 定义类class SweetPotato(): def __init__(self): # 被烤的时间 self.cook_time = 0 # 地瓜的状态 self.cook_static = '生的' # 调料列表 self.condiments = [] def cook(self, time): &quot;&quot;&quot;烤地瓜的方法&quot;&quot;&quot; self.cook_time += time if 0 &lt;= self.cook_time &lt; 3: self.cook_static = '生的' elif 3 &lt;= self.cook_time &lt; 5: self.cook_static = '半生不熟' elif 5 &lt;= self.cook_time &lt; 8: self.cook_static = '熟了' elif self.cook_time &gt;= 8: self.cook_static = '烤糊了' def add_condiments(self, condiment): &quot;&quot;&quot;添加调料&quot;&quot;&quot; self.condiments.append(condiment) def __str__(self): return f'这个地瓜烤了{self.cook_time}分钟, 状态是{self.cook_static}, 添加的调料有{self.condiments}'digua1 = SweetPotato()print(digua1)digua1.cook(2)digua1.add_condiments('酱油')print(digua1)digua1.cook(2)digua1.add_condiments('辣椒面儿')print(digua1)digua1.cook(2)print(digua1)digua1.cook(2)print(digua1) 搬家具将小于房子剩余面积的家具摆放到房子中步骤分析需求涉及两个事物：房子 和 家具，故被案例涉及两个类：房子类 和 家具类。定义类 房子类 实例属性 房子地理位置 房子占地面积 房子剩余面积 房子内家具列表 实例方法 容纳家具 显示房屋信息 家具类 家具名称 家具占地面积创建对象并调用相关方法 家具类 123456class Furniture(): def __init__(self, name, area): # 家具名字 self.name = name # 家具占地面积 self.area = area 房子类 1234567891011121314151617181920class Home(): def __init__(self, address, area): # 地理位置 self.address = address # 房屋面积 self.area = area # 剩余面积 self.free_area = area # 家具列表 self.furniture = [] def __str__(self): return f'房子坐落于{self.address}, 占地面积{self.area}, 剩余面积{self.free_area}, 家具有{self.furniture}' def add_furniture(self, item): &quot;&quot;&quot;容纳家具&quot;&quot;&quot; if self.free_area &gt;= item.area: self.furniture.append(item.name) # 家具搬入后，房屋剩余面积 = 之前剩余面积 - 该家具面积 self.free_area -= item.area else: print('家具太大，剩余面积不足，无法容纳') 创建对象并调用实例属性和方法1234567891011121314bed = Furniture('双人床', 6)jia1 = Home('北京', 1200)print(jia1)jia1.add_furniture(bed)print(jia1)sofa = Furniture('沙发', 10)jia1.add_furniture(sofa)print(jia1)ball = Furniture('篮球场', 1500)jia1.add_furniture(ball)print(jia1) 魔法方法 __init__(): 初始化 __str__():输出对象信息 __del__():删除对象时调用 面向对象-继承继承的概念生活中的继承，一般指的是子女继承父辈的财产。 拓展1：经典类或旧式类:不由任意内置类型派生出的类，称之为经典类。123class 类名: 代码 ...... 拓展2：新式类12class 类名(object): 代码 Python面向对象的继承指的是多个类之间的所属关系，即子类默认继承父类的所有属性和方法，具体如下：1234567891011# 父类Aclass A(object): def __init__(self): self.num = 1 def info_print(self): print(self.num)# 子类Bclass B(A): passresult = B()result.info_print() # 1 在Python中，所有类默认继承object类，object类是顶级类或基类；其他子类叫做派生类。 单继承 故事主线：一个煎饼果子老师傅，在煎饼果子界摸爬滚打多年，研发了一套精湛的摊煎饼果子的技术。师父要把这套技术传授给他的唯一的最得意的徒弟。分析：徒弟是不是要继承师父的所有技术？ 123456789101112131415# 1. 师父类class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')# 2. 徒弟类class Prentice(Master): pass# 3. 创建对象daqiudaqiu = Prentice()# 4. 对象访问实例属性print(daqiu.kongfu)# 5. 对象调用实例方法daqiu.make_cake() 多继承 故事推进：daqiu是个爱学习的好孩子，想学习更多的煎饼果子技术，于是，在百度搜索到黑马程序员，报班学习煎饼果子技术。 所谓多继承意思就是一个类同时继承了多个父类。 123456789101112131415161718class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print( &quot;%s&quot; % self.kongfu)# 创建学校类class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print( &quot;%s&quot; % self.kongfu)class Prentice(School, Master): passdaqiu = Prentice()print(daqiu.kongfu)daqiu.make_cake()#[煎饼果子配方]#[煎饼果子配方] 注意：当一个类有多个父类的时候，默认使用第一个父类的同名属性和方法。 子类重写父类同名方法和属性 故事：daqiu掌握了师父和培训的技术后，自己潜心钻研出自己的独门配方的一套全新的煎饼果子技术。 12345678910111213141516171819202122232425class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')# 独创配方class Prentice(School, Master): def __init__(self): self.kongfu = '[独创煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')daqiu = Prentice()print(daqiu.kongfu)daqiu.make_cake()print(Prentice.__mro__) 子类和父类具有同名属性和方法，默认使用子类的同名属性和方法。 子类调用父类的同名方法和属性 故事：很多顾客都希望也能吃到古法和新的技术的煎饼果子。 123456789101112131415161718192021222324252627282930313233343536373839class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class Prentice(School, Master): def __init__(self): self.kongfu = '[独创煎饼果子配方]' def make_cake(self): # 如果是先调用了父类的属性和方法，父类属性会覆盖子类属性，故在调用属性前，先调用自己子类的初始化 self.__init__() print(f'运用{self.kongfu}制作煎饼果子') # 调用父类方法，但是为保证调用到的也是父类的属性，必须在调用方法前调用父类的初始化 def make_master_cake(self): Master.__init__(self) Master.make_cake(self) def make_school_cake(self): School.__init__(self) School.make_cake(self)daqiu = Prentice()daqiu.make_cake()daqiu.make_master_cake()daqiu.make_school_cake()daqiu.make_cake() 多层继承 故事：N年后，daqiu老了，想要把所有技术传承给自己的徒弟。 1234567891011121314151617181920212223242526272829303132333435363738class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class Prentice(School, Master): def __init__(self): self.kongfu = '[独创煎饼果子配方]' def make_cake(self): self.__init__() print(f'运用{self.kongfu}制作煎饼果子') def make_master_cake(self): Master.__init__(self) Master.make_cake(self) def make_school_cake(self): School.__init__(self) School.make_cake(self)# 徒孙类class Tusun(Prentice): passxiaoqiu = Tusun()xiaoqiu.make_cake()xiaoqiu.make_school_cake()xiaoqiu.make_master_cake() super()调用父类方法12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(Master): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子') # 方法2.1 # super(School, self).__init__() # super(School, self).make_cake() # 方法2.2 super().__init__() super().make_cake()class Prentice(School): def __init__(self): self.kongfu = '[独创煎饼果子技术]' def make_cake(self): self.__init__() print(f'运用{self.kongfu}制作煎饼果子') # 子类调用父类的同名方法和属性：把父类的同名属性和方法再次封装 def make_master_cake(self): Master.__init__(self) Master.make_cake(self) def make_school_cake(self): School.__init__(self) School.make_cake(self) # 一次性调用父类的同名属性和方法 def make_old_cake(self): # 方法一：代码冗余；父类类名如果变化，这里代码需要频繁修改 # Master.__init__(self) # Master.make_cake(self) # School.__init__(self) # School.make_cake(self) # 方法二: super() # 方法2.1 super(当前类名, self).函数() # super(Prentice, self).__init__() # super(Prentice, self).make_cake() # 方法2.2 super().函数() super().__init__() super().make_cake()daqiu = Prentice()daqiu.make_old_cake() 注意：使用super() 可以自动查找父类。调用顺序遵循 __mro__ 类属性的顺序。比较适合单继承使用。 私有权限定义私有属性和方法在Python中，可以为实例属性和方法设置私有权限，即设置某个实例属性或实例方法不继承给子类。 故事：daqiu把技术传承给徒弟的同时，不想把自己的钱(2000000个亿)继承给徒弟，这个时候就要为钱这个实例属性设置私有权限。 ·设置私有权限的方法：在属性名和方法名 前面 加上两个下划线 __。· 1234567891011121314151617181920212223242526272829303132333435363738394041424344class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class Prentice(School, Master): def __init__(self): self.kongfu = '[独创煎饼果子配方]' # 定义私有属性 self.__money = 2000000 # 定义私有方法 def __info_print(self): print(self.kongfu) print(self.__money) def make_cake(self): self.__init__() print(f'运用{self.kongfu}制作煎饼果子') def make_master_cake(self): Master.__init__(self) Master.make_cake(self) def make_school_cake(self): School.__init__(self) School.make_cake(self)# 徒孙类class Tusun(Prentice): passdaqiu = Prentice()# 对象不能访问私有属性和私有方法# print(daqiu.__money)# daqiu.__info_print()xiaoqiu = Tusun()# 子类无法继承父类的私有属性和私有方法# print(xiaoqiu.__money) # 无法访问实例属性__money# xiaoqiu.__info_print() 注意：私有属性和私有方法只能在类里面访问和修改。 获取和修改私有属性值在Python中，一般定义函数名get_xx用来获取私有属性，定义set_xx用来修改私有属性值。 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849class Master(object): def __init__(self): self.kongfu = '[古法煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class School(object): def __init__(self): self.kongfu = '[黑马煎饼果子配方]' def make_cake(self): print(f'运用{self.kongfu}制作煎饼果子')class Prentice(School, Master): def __init__(self): self.kongfu = '[独创煎饼果子配方]' self.__money = 2000000 # 获取私有属性 def get_money(self): return self.__money # 修改私有属性 def set_money(self): self.__money = 500 def __info_print(self): print(self.kongfu) print(self.__money) def make_cake(self): self.__init__() print(f'运用{self.kongfu}制作煎饼果子') def make_master_cake(self): Master.__init__(self) Master.make_cake(self) def make_school_cake(self): School.__init__(self) School.make_cake(self)# 徒孙类class Tusun(Prentice): passdaqiu = Prentice()xiaoqiu = Tusun()# 调用get_money函数获取私有属性money的值print(xiaoqiu.get_money())# 调用set_money函数修改私有属性money的值xiaoqiu.set_money()print(xiaoqiu.get_money()) 异常了解异常当检测到一个错误时，解释器就无法继续执行了，反而出现了一些错误的提示，这就是所谓的”异常”。 例如：以r方式打开一个不存在的文件。 1open('test.txt', 'r') 异常的写法1234try: 可能发生错误的代码except: 如果出现异常执行的代码 需求：尝试以r模式打开文件，如果文件不存在，则以w方式打开。 1234try: f = open('test.txt', 'r')except: f = open('test.txt', 'w') 捕获指定异常1234try: 可能发生错误的代码except 异常类型: 如果捕获到该异常类型执行的代码 1234try: print(num)except NameError: print('有错误') 注意： 如果尝试执行的代码的异常类型和要捕获的异常类型不一致，则无法捕获异常。 一般try下方只放一行尝试执行的代码。 捕获多个指定异常当捕获多个异常时，可以把要捕获的异常类型的名字，放到except 后，并使用元组的方式进行书写。 12345try: print(1/0)except (NameError, ZeroDivisionError): print('有错误') 捕获异常描述信息1234try: print(num)except (NameError, ZeroDivisionError) as result: print(result) 捕获所有异常Exception是所有程序异常类的父类。 1234try: print(num)except Exception as result: print(result) 异常的elseelse表示的是如果没有异常要执行的代码。 123456try: print(1)except Exception as result: print(result)else: print('我是else，是没有异常的时候执行的代码') 异常的finallyfinally表示的是无论是否异常都要执行的代码，例如关闭文件。 12345678try: f = open('test.txt', 'r')except Exception as result: f = open('test.txt', 'w')else: print('没有异常，真开心')finally: f.close() 异常的传递​ 1. 尝试只读方式打开test.txt文件，如果文件存在则读取文件内容，文件不存在则提示用户即可。 ​ 2. 读取内容要求：尝试循环读取内容，读取过程中如果检测到用户意外终止程序，则except捕获异常并提示用户。 12345678910111213141516171819import timetry: f = open('test.txt') try: while True: content = f.readline() if len(content) == 0: break time.sleep(2) print(content) except: # 如果在读取文件的过程中，产生了异常，那么就会捕获到 # 比如 按下了 ctrl+c print('意外终止了读取数据') finally: f.close() print('关闭文件')except: print(&quot;没有这个文件&quot;) 自定义异常在Python中，抛出自定义异常的语法为 raise 异常类对象。 需求：密码长度不足，则报异常（用户输入密码，如果输入的长度不足3位，则报错，即抛出自定义异常，并捕获该异常）。 12345678910111213141516171819202122# 自定义异常类，继承Exceptionclass ShortInputError(Exception): def __init__(self, length, min_len): self.length = length self.min_len = min_len # 设置抛出异常的描述信息 def __str__(self): return f'你输入的长度是{self.length}, 不能少于{self.min_len}个字符'def main(): try: con = input('请输入密码：') if len(con) &lt; 3: raise ShortInputError(len(con), 3) except Exception as result: print(result) else: print('密码已经输入完成')main() 模块和包模块Python 模块(Module)，是一个 Python 文件，以 .py 结尾，包含了 Python 对象定义和Python语句。模块能定义函数，类和变量，模块里也能包含可执行的代码。 导入模块导入模块的方式 import 模块名 from 模块名 import 功能名 from 模块名 import * import 模块名 as 别名 from 模块名 import 功能名 as 别名 import12345# 1. 导入模块import 模块名import 模块名1, 模块名2...# 2. 调用功能模块名.功能名() 12import mathprint(math.sqrt(9)) # 3.0 from..import..1from 模块名 import 功能1, 功能2, 功能3... 12from math import sqrtprint(sqrt(9)) from .. import *1from 模块名 import * 12from math import *print(sqrt(9)) as定义别名1234# 模块定义别名import 模块名 as 别名# 功能定义别名from 模块名 import 功能 as 别名 12345678# 模块别名import time as tttt.sleep(2)print('hello')# 功能别名from time import sleep as slsl(2)print('hello') 制作模块在Python中，每个Python文件都可以作为一个模块，模块的名字就是文件的名字。也就是说自定义模块名必须要符合标识符命名规则。 定义模块新建一个Python文件，命名为my_module1.py，并定义testA函数。 12def testA(a, b): print(a + b) 测试模块在实际开中，当一个开发人员编写完一个模块后，为了让模块能够在项目中达到想要的效果，这个开发人员会自行在py文件中添加一些测试信息.，例如，在my_module1.py文件中添加测试代码。 12345def testA(a, b): print(a + b)testA(1, 1) 此时，无论是当前文件，还是其他已经导入了该模块的文件，在运行的时候都会自动执行testA函数的调用。解决办法如下：·main函数· 12345def testA(a, b): print(a + b)# 只在当前文件中调用该函数，其他导入的文件内不符合该条件，则不执行testA函数调用if __name__ == '__main__': testA(1, 1) 调用模块12import my_module1my_module1.testA(1, 1) 注意事项如果使用from .. import ..或from .. import *导入多个模块的时候，且模块内有同名功能。当调用这个同名功能的时候，调用到的是后面导入的模块的功能。 体验1234567891011# 模块1代码def my_test(a, b): print(a + b)# 模块2代码def my_test(a, b): print(a - b)# 导入模块和调用功能代码from my_module1 import my_testfrom my_module2 import my_test# my_test函数是模块2中的函数my_test(1, 1) 模块定位顺序当导入一个模块，Python解析器对模块位置的搜索顺序是： 当前目录 如果不在当前目录，Python则搜索在shell变量PYTHONPATH下的每个目录。 如果都找不到，Python会察看默认路径。UNIX下，默认路径一般为/usr/local/lib/python/ 模块搜索路径存储在system模块的sys.path变量中。变量里包含当前目录，PYTHONPATH和由安装过程决定的默认目录。 注意 自己的文件名不要和已有模块名重复，否则导致模块功能无法使用 使用from 模块名 import 功能的时候，如果功能名字重复，调用到的是最后定义或导入的功能。__all__ 如果一个模块文件中有__all__变量，当使用from xxx import *导入时，只能导入这个列表中的元素。 my_module1模块代码123456789__all__ = ['testA']def testA(): print('testA')def testB(): print('testB') 导入模块的文件代码123from my_module1 import *testA()testB() 包包将有联系的模块组织在一起，即放到同一个文件夹下，并且在这个文件夹创建一个名字为__init__.py 文件，那么这个文件夹就称之为包。 制作包[New] — [Python Package] — 输入包名 — [OK] — 新建功能模块(有联系的模块)。 注意：新建包后，包内部会自动创建__init__.py文件，这个文件控制着包的导入行为。 新建包mypackage 新建包内模块：my_module1 和 my_module2 模块内代码如下123456# my_module1print(1)def info_print1(): print('my_module1') 123456# my_module2print(2)def info_print2(): print('my_module2') 导入包方法一123import 包名.模块名包名.模块名.目标 123import my_package.my_module1my_package.my_module1.info_print1() 方法二 注意：必须在__init__.py文件中添加__all__ = []，控制允许导入的模块列表。 12from 包名 import *模块名.目标 123from my_package import *my_module1.info_print1() 课程：面向对象版学员管理系统系统需求使用面向对象编程思想完成学员管理系统的开发，具体如下： 系统要求：学员数据存储在文件中 系统功能：添加学员、删除学员、修改学员信息、查询学员信息、显示所有学员信息、保存学员信息及退出系统等功能。准备程序文件 角色分析 学员 管理系统 工作中注意事项 为了方便维护代码，一般一个角色一个程序文件； 项目要有主程序入口，习惯为main.py 创建程序文件创建项目目录，例如：StudentManagerSystem程序文件如下： 程序入口文件：main.py 学员文件：student.py 管理系统文件：managerSystem.pystudent.py需求： 学员信息包含：姓名、性别、手机号； 添加__str__魔法方法，方便查看学员对象信息1234567class Student(object): def __init__(self, name, gender, tel): self.name = name self.gender = gender self.tel = tel def __str__(self): return f'{self.name}, {self.gender}, {self.tel}' managerSystem.py需求： 存储数据的位置：文件(student.data) 加载文件数据 修改数据后保存到文件 存储数据的形式：列表存储学员对象 系统功能 添加学员 删除学员 修改学员 查询学员信息 显示所有学员信息 保存学员信息 退出系统定义类1234class StudentManager(object): def __init__(self): # 存储数据所用的列表 self.student_list = [] 管理系统框架 需求：系统功能循环使用，用户输入不同的功能序号执行不同的功能。 步骤 定义程序入口函数 加载数据 显示功能菜单 用户输入功能序号 根据用户输入的功能序号执行不同的功能 定义系统功能函数，添加、删除学员等1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768class StudentManager(object): def __init__(self): # 存储数据所用的列表 self.student_list = [] # 一. 程序入口函数，启动程序后执行的函数 def run(self): # 1. 加载学员信息 self.load_student() while True: # 2. 显示功能菜单 self.show_menu() # 3. 用户输入功能序号 menu_num = int(input('请输入您需要的功能序号：')) # 4 根据用户输入的功能序号执行不同的功能 if menu_num == 1: # 添加学员 self.add_student() elif menu_num == 2: # 删除学员 self.del_student() elif menu_num == 3: # 修改学员信息 self.modify_student() elif menu_num == 4: # 查询学员信息 self.search_student() elif menu_num == 5: # 显示所有学员信息 self.show_student() elif menu_num == 6: # 保存学员信息 self.save_student() elif menu_num == 7: # 退出系统 break # 二. 定义功能函数 # 2.1 显示功能菜单 @staticmethod def show_menu(): print('请选择如下功能-----------------') print('1:添加学员') print('2:删除学员') print('3:修改学员信息') print('4:查询学员信息') print('5:显示所有学员信息') print('6:保存学员信息') print('7:退出系统') # 2.2 添加学员 def add_student(self): pass # 2.3 删除学员 def del_student(self): pass # 2.4 修改学员信息 def modify_student(self): pass # 2.5 查询学员信息 def search_student(self): pass # 2.6 显示所有学员信息 def show_student(self): pass # 2.7 保存学员信息 def save_student(self): pass # 2.8 加载学员信息 def load_student(self): pass main.py123456# 1. 导入managerSystem模块from managerSystem import *# 2. 启动学员管理系统if __name__ == '__main__': student_manager = StudentManager() student_manager.run() 定义系统功能函数添加功能 需求：用户输入学员姓名、性别、手机号，将学员添加到系统。 步骤 用户输入姓名、性别、手机号 创建该学员对象 将该学员对象添加到列表 代码12345678910111213141516171819# 添加学员函数内部需要创建学员对象，故先导入student模块from student import *class StudentManager(object): ...... # 2.2 添加学员 def add_student(self): # 1. 用户输入姓名、性别、手机号 name = input('请输入您的姓名：') gender = input('请输入您的性别：') tel = input('请输入您的手机号：') # 2. 创建学员对象：先导入学员模块，再创建对象 student = Student(name, gender, tel) # 3. 将该学员对象添加到列表 self.student_list.append(student) # 打印信息 print(self.student_list) print(student) 删除学员 需求：用户输入目标学员姓名，如果学员存在则删除该学员。 步骤 用户输入目标学员姓名 遍历学员数据列表，如果用户输入的学员姓名存在则删除，否则则提示该学员不存在。 代码12345678910111213# 2.3 删除学员：删除指定姓名的学员def del_student(self): # 1. 用户输入目标学员姓名 del_name = input('请输入要删除的学员姓名：') # 2. 如果用户输入的目标学员存在则删除，否则提示学员不存在 for i in self.student_list: if i.name == del_name: self.student_list.remove(i) break else: print('查无此人！') # 打印学员列表，验证删除功能 print(self.student_list) 修改学员信息 需求：用户输入目标学员姓名，如果学员存在则修改该学员信息。 步骤 用户输入目标学员姓名； 遍历学员数据列表，如果用户输入的学员姓名存在则修改学员的姓名、性别、手机号数据，否则则提示该学员不存在。 代码1234567891011121314# 2.4 修改学员信息def modify_student(self): # 1. 用户输入目标学员姓名 modify_name = input('请输入要修改的学员的姓名：') # 2. 如果用户输入的目标学员存在则修改姓名、性别、手机号等数据，否则提示学员不存在 for i in self.student_list: if i.name == modify_name: i.name = input('请输入学员姓名：') i.gender = input('请输入学员性别：') i.tel = input('请输入学员手机号：') print(f'修改该学员信息成功，姓名{i.name},性别{i.gender}, 手机号{i.tel}') break else: print('查无此人！') 查询学员信息 需求：用户输入目标学员姓名，如果学员存在则打印该学员信息 步骤 用户输入目标学员姓名 遍历学员数据列表，如果用户输入的学员姓名存在则打印学员信息，否则提示该学员不存在。 代码1234567891011# 2.5 查询学员信息def search_student(self): # 1. 用户输入目标学员姓名 search_name = input('请输入要查询的学员的姓名：') # 2. 如果用户输入的目标学员存在，则打印学员信息，否则提示学员不存在 for i in self.student_list: if i.name == search_name: print(f'姓名{i.name},性别{i.gender}, 手机号{i.tel}') break else: print('查无此人!') 显示所有学员信息 打印所有学员信息 步骤 遍历学员数据列表，打印所有学员信息 代码12345# 2.6 显示所有学员信息def show_student(self): print('姓名	性别	手机号') for i in self.student_list: print(f'{i.name}	{i.gender}	{i.tel}') 保存学员信息 需求：将修改后的学员数据保存到存储数据的文件。 步骤 打开文件 文件写入数据 关闭文件 思考 文件写入的数据是学员对象的内存地址吗？ 文件内数据要求的数据类型是什么？ 拓展__dict__123456789class A(object): a = 0 def __init__(self): self.b = 1aa = A()# 返回类内部所有属性和方法对应的字典print(A.__dict__)# 返回实例属性和值组成的字典print(aa.__dict__) 在Python中 代码12345678910111213# 2.7 保存学员信息def save_student(self): # 1. 打开文件 f = open('student.data', 'w') # 2. 文件写入学员数据 # 注意1：文件写入的数据不能是学员对象的内存地址，需要把学员数据转换成列表字典数据再做存储 new_list = [i.__dict__ for i in self.student_list] # [{'name': 'aa', 'gender': 'nv', 'tel': '111'}] print(new_list) # 注意2：文件内数据要求为字符串类型，故需要先转换数据类型为字符串才能文件写入数据 f.write(str(new_list)) # 3. 关闭文件 f.close() 加载学员信息 需求：每次进入系统后，修改的数据是文件里面的数据 步骤 尝试以&quot;r&quot;模式打开学员数据文件，如果文件不存在则以&quot;w&quot;模式打开文件 如果文件存在则读取数据并存储数据 读取数据 转换数据类型为列表并转换列表内的字典为对象 存储学员数据到学员列表 关闭文件 代码12345678910111213141516# 2.8 加载学员信息def load_student(self): # 尝试以&quot;r&quot;模式打开数据文件，文件不存在则提示用户；文件存在（没有异常）则读取数据 try: f = open('student.data', 'r') except: f = open('student.data', 'w') else: # 1. 读取数据 data = f.read() # 2. 文件中读取的数据都是字符串且字符串内部为字典数据，故需要转换数据类型再转换字典为对象后存储到学员列表 new_list = eval(data) self.student_list = [Student(i['name'], i['gender'], i['tel']) for i in new_list] finally: # 3. 关闭文件 f.close() 多任务的介绍Python 多进程导入进程包12#导入进程包import multiprocessing Process进程类的说明1Process([group [, target [, name [, args [, kwargs]]]]]) group：指定进程组，目前只能使用None target：执行的目标任务名 name：进程名字 args：以元组方式给执行任务传参 kwargs：以字典方式给执行任务传参Process创建的实例对象的常用方法: start()：启动子进程实例（创建子进程） join()：等待子进程执行结束 terminate()：不管任务是否完成，立即终止子进程Process创建的实例对象的常用属性: name：当前进程的别名，默认为Process-N，N为从1开始递增的整数多进程完成多任务的代码1234567891011121314151617181920212223import multiprocessingimport time# 跳舞任务def dance(): for i in range(5): print(&quot;跳舞中...&quot;) time.sleep(0.2)# 唱歌任务def sing(): for i in range(5): print(&quot;唱歌中...&quot;) time.sleep(0.2)if __name__ == '__main__': # 创建跳舞的子进程 # group: 表示进程组，目前只能使用None # target: 表示执行的目标任务名(函数名、方法名) # name: 进程名称, 默认是Process-1, ..... dance_process = multiprocessing.Process(target=dance, name=&quot;myprocess1&quot;) sing_process = multiprocessing.Process(target=sing) # 启动子进程执行对应的任务 dance_process.start() sing_process.start() 执行结果:唱歌中…跳舞中…唱歌中…跳舞中…唱歌中…跳舞中…唱歌中…跳舞中…唱歌中…跳舞中… 获取进程编号获取进程编号的目的获取进程编号的目的是验证主进程和子进程的关系，可以得知子进程是由那个主进程创建出来的。获取进程编号的两种操作 获取当前进程编号 获取当前父进程编号 是OS模块获取当前进程编号os.getpid() 表示获取当前进程编号123456789101112131415161718192021222324252627282930313233343536373839import multiprocessingimport timeimport os# 跳舞任务def dance(): # 获取当前进程的编号 print(&quot;dance:&quot;, os.getpid()) # 获取当前进程 print(&quot;dance:&quot;, multiprocessing.current_process()) for i in range(5): print(&quot;跳舞中...&quot;) time.sleep(0.2) # 扩展:根据进程编号杀死指定进程 os.kill(os.getpid(), 9)# 唱歌任务def sing(): # 获取当前进程的编号 print(&quot;sing:&quot;, os.getpid()) # 获取当前进程 print(&quot;sing:&quot;, multiprocessing.current_process()) for i in range(5): print(&quot;唱歌中...&quot;) time.sleep(0.2)if __name__ == '__main__': # 获取当前进程的编号 print(&quot;main:&quot;, os.getpid()) # 获取当前进程 print(&quot;main:&quot;, multiprocessing.current_process()) # 创建跳舞的子进程 # group: 表示进程组，目前只能使用None # target: 表示执行的目标任务名(函数名、方法名) # name: 进程名称, 默认是Process-1, ..... dance_process = multiprocessing.Process(target=dance, name=&quot;myprocess1&quot;) sing_process = multiprocessing.Process(target=sing) # 启动子进程执行对应的任务 dance_process.start() sing_process.start() 执行结果:main: 70763main: &lt;_MainProcess(MainProcess, started)&gt;dance: 70768dance: &lt;Process(myprocess1, started)&gt;跳舞中…sing: 70769sing: &lt;Process(Process-2, started)&gt;唱歌中…唱歌中…唱歌中…唱歌中…唱歌中… 获取当前父进程编号os.getppid() 表示获取当前父进程编号12345678910111213141516171819202122232425262728293031323334353637383940414243import multiprocessingimport timeimport os# 跳舞任务def dance(): # 获取当前进程的编号 print(&quot;dance:&quot;, os.getpid()) # 获取当前进程 print(&quot;dance:&quot;, multiprocessing.current_process()) # 获取父进程的编号 print(&quot;dance的父进程编号:&quot;, os.getppid()) for i in range(5): print(&quot;跳舞中...&quot;) time.sleep(0.2) # 扩展:根据进程编号杀死指定进程 os.kill(os.getpid(), 9)# 唱歌任务def sing(): # 获取当前进程的编号 print(&quot;sing:&quot;, os.getpid()) # 获取当前进程 print(&quot;sing:&quot;, multiprocessing.current_process()) # 获取父进程的编号 print(&quot;sing的父进程编号:&quot;, os.getppid()) for i in range(5): print(&quot;唱歌中...&quot;) time.sleep(0.2)if __name__ == '__main__': # 获取当前进程的编号 print(&quot;main:&quot;, os.getpid()) # 获取当前进程 print(&quot;main:&quot;, multiprocessing.current_process()) # 创建跳舞的子进程 # group: 表示进程组，目前只能使用None # target: 表示执行的目标任务名(函数名、方法名) # name: 进程名称, 默认是Process-1, ..... dance_process = multiprocessing.Process(target=dance, name=&quot;myprocess1&quot;) sing_process = multiprocessing.Process(target=sing) # 启动子进程执行对应的任务 dance_process.start() sing_process.start() main: 70860main: &lt;_MainProcess(MainProcess, started)&gt;dance: 70861dance: &lt;Process(myprocess1, started)&gt;dance的父进程编号: 70860跳舞中…sing: 70862sing: &lt;Process(Process-2, started)&gt;sing的父进程编号: 70860唱歌中…唱歌中…唱歌中…唱歌中…唱歌中… 进程执行带有参数的任务进程执行带有参数的任务的介绍我们使用进程执行的任务是没有参数的，假如我们使用进程执行的任务带有参数，如何给函数传参呢?Process类执行任务并给任务传参数有两种方式: args 表示以元组的方式给执行任务传参 kwargs 表示以字典方式给执行任务传参 args参数的使用 123456789101112131415import multiprocessingimport time# 带有参数的任务def task(count): for i in range(count): print(&quot;任务执行中..&quot;) time.sleep(0.2) else: print(&quot;任务执行完成&quot;)if __name__ == '__main__': # 创建子进程 # args: 以元组的方式给任务传入参数 sub_process = multiprocessing.Process(target=task, args=(5,)) sub_process.start() 任务执行中..任务执行中..任务执行中..任务执行中..任务执行中..任务执行完成kwargs参数的使用 12345678910111213141516import multiprocessingimport time# 带有参数的任务def task(count): for i in range(count): print(&quot;任务执行中..&quot;) time.sleep(0.2) else: print(&quot;任务执行完成&quot;)if __name__ == '__main__': # 创建子进程 # kwargs: 表示以字典方式传入参数 sub_process = multiprocessing.Process(target=task, kwargs={&quot;count&quot;: 3}) sub_process.start() 任务执行中..任务执行中..任务执行中..任务执行完成 进程的注意点进程的注意点介绍: 进程之间不共享全局变量 主进程会等待所有的子进程执行结束再结束进程之间不共享全局变量:123456789101112131415161718192021222324252627282930import multiprocessingimport time# 定义全局变量g_list = list()# 添加数据的任务def add_data(): for i in range(5): g_list.append(i) print(&quot;add:&quot;, i) time.sleep(0.2) # 代码执行到此，说明数据添加完成 print(&quot;add_data:&quot;, g_list)def read_data(): print(&quot;read_data&quot;, g_list)if __name__ == '__main__': # 创建添加数据的子进程 add_data_process = multiprocessing.Process(target=add_data) # 创建读取数据的子进程 read_data_process = multiprocessing.Process(target=read_data) # 启动子进程执行对应的任务 add_data_process.start() # 主进程等待添加数据的子进程执行完成以后程序再继续往下执行，读取数据 add_data_process.join() read_data_process.start() print(&quot;main:&quot;, g_list) # 总结: 多进程之间不共享全局变量 add: 0add: 1add: 2add: 3add: 4add_data: [0, 1, 2, 3, 4]main: []read_data [] 创建子进程会对主进程资源进行拷贝，也就是说子进程是主进程的一个副本，好比是一对双胞胎，之所以进程之间不共享全局变量，是因为操作的不是同一个进程里面的全局变量，只不过不同进程里面的全局变量名字相同而已。 主进程会等待所有的子进程执行结束再结束假如我们现在创建一个子进程，这个子进程执行完大概需要2秒钟，现在让主进程执行0.5秒钟就退出程序，查看一下执行结果. 1234567891011121314151617import multiprocessingimport time# 定义进程所需要执行的任务def task(): for i in range(10): print(&quot;任务执行中...&quot;) time.sleep(0.2)if __name__ == '__main__': # 创建子进程 sub_process = multiprocessing.Process(target=task) sub_process.start() # 主进程延时0.5秒钟 time.sleep(0.5) print(&quot;over&quot;) exit() # 总结： 主进程会等待所有的子进程执行完成以后程序再退出 任务执行中…任务执行中…任务执行中…over任务执行中…任务执行中…任务执行中…任务执行中…任务执行中…任务执行中…任务执行中… 主进程会等待所有的子进程执行结束再结束,假如我们就让主进程执行0.5秒钟，子进程就销毁不再执行，那怎么办呢?我们可以设置守护主进程 或者 在主进程退出之前 让子进程销毁 守护主进程:守护主进程就是主进程退出子进程销毁不再执行 子进程销毁:子进程执行结束123456789101112131415161718192021import multiprocessingimport time# 定义进程所需要执行的任务def task(): for i in range(10): print(&quot;任务执行中...&quot;) time.sleep(0.2)if __name__ == '__main__': # 创建子进程 sub_process = multiprocessing.Process(target=task) # 设置守护主进程，主进程退出子进程直接销毁，子进程的生命周期依赖与主进程 # sub_process.daemon = True sub_process.start() time.sleep(0.5) print(&quot;over&quot;) # 让子进程销毁 sub_process.terminate() exit() # 总结： 主进程会等待所有的子进程执行完成以后程序再退出 # 如果想要主进程退出子进程销毁，可以设置守护主进程或者在主进程退出之前让子进程销毁 多线程的使用导入线程模块12#导入线程模块import threading 线程类Thread参数说明1Thread([group [, target [, name [, args [, kwargs]]]]]) group: 线程组，目前只能使用None target: 执行的目标任务名 args: 以元组的方式给执行任务传参 kwargs: 以字典方式给执行任务传参 name: 线程名，一般不用设置启动线程 启动线程使用start方法多线程完成多任务1234567891011121314151617181920212223242526272829import threadingimport time# 唱歌任务def sing(): # 扩展： 获取当前线程 # print(&quot;sing当前执行的线程为：&quot;, threading.current_thread()) for i in range(3): print(&quot;正在唱歌...%d&quot; % i) time.sleep(1)# 跳舞任务def dance(): # 扩展： 获取当前线程 # print(&quot;dance当前执行的线程为：&quot;, threading.current_thread()) for i in range(3): print(&quot;正在跳舞...%d&quot; % i) time.sleep(1)if __name__ == '__main__': # 扩展： 获取当前线程 # print(&quot;当前执行的线程为：&quot;, threading.current_thread()) # 创建唱歌的线程 # target： 线程执行的函数名 sing_thread = threading.Thread(target=sing) # 创建跳舞的线程 dance_thread = threading.Thread(target=dance) # 开启线程 sing_thread.start() dance_thread.start() 正在唱歌…0正在跳舞…0正在唱歌…1正在跳舞…1正在唱歌…2正在跳舞…2 线程执行带有参数的任务线程执行带有参数的任务的介绍前面我们使用线程执行的任务是没有参数的，假如我们使用线程执行的任务带有参数，如何给函数传参呢?Thread类执行任务并给任务传参数有两种方式: args 表示以元组的方式给执行任务传参 kwargs 表示以字典方式给执行任务传参 args参数的使用 12345678910111213141516import threadingimport time# 带有参数的任务def task(count): for i in range(count): print(&quot;任务执行中..&quot;) time.sleep(0.2) else: print(&quot;任务执行完成&quot;)if __name__ == '__main__': # 创建子线程 # args: 以元组的方式给任务传入参数 sub_thread = threading.Thread(target=task, args=(5,)) sub_thread.start() 任务执行中..任务执行中..任务执行中..任务执行中..任务执行中..任务执行完成kwargs参数的使用 12345678910111213141516import threadingimport time# 带有参数的任务def task(count): for i in range(count): print(&quot;任务执行中..&quot;) time.sleep(0.2) else: print(&quot;任务执行完成&quot;)if __name__ == '__main__': # 创建子线程 # kwargs: 表示以字典方式传入参数 sub_thread = threading.Thread(target=task, kwargs={&quot;count&quot;: 3}) sub_thread.start() 任务执行中..任务执行中..任务执行中..任务执行完成 线程的注意点 线程之间执行是无序的 主线程会等待所有的子线程执行结束再结束 线程之间共享全局变量 线程之间共享全局变量数据出现错误问题线程之间执行是无序的 线程之间执行是无序的，它是由cpu调度决定的 ，cpu调度哪个线程，哪个线程就先执行，没有调度的线程不能执行。 进程之间执行也是无序的，它是由操作系统调度决定的，操作系统调度哪个进程，哪个进程就先执行，没有调度的进程不能执行。12345678910111213import threadingimport timedef task(): time.sleep(1) print(&quot;当前线程:&quot;, threading.current_thread().name)if __name__ == '__main__': for _ in range(5): sub_thread = threading.Thread(target=task) sub_thread.start() 当前线程: Thread-1当前线程: Thread-2当前线程: Thread-4当前线程: Thread-5当前线程: Thread-3 主线程会等待所有的子线程执行结束再结束假如我们现在创建一个子线程，这个子线程执行完大概需要2.5秒钟，现在让主线程执行1秒钟就退出程序，查看一下执行结果123456789101112131415import threadingimport time# 测试主线程是否会等待子线程执行完成以后程序再退出def show_info(): for i in range(5): print(&quot;test:&quot;, i) time.sleep(0.5)if __name__ == '__main__': sub_thread = threading.Thread(target=show_info) sub_thread.start() # 主线程延时1秒 time.sleep(1) print(&quot;over&quot;) test: 0test: 1overtest: 2test: 3test: 4主线程会等待所有的子线程执行结束再结束,假如我们就让主线程执行1秒钟，子线程就销毁不再执行，那怎么办呢? 我们可以设置守护主线程守护主线程:守护主线程就是主线程退出子线程销毁不再执行设置守护主线程有两种方式： threading.Thread(target=show_info, daemon=True) 线程对象.setDaemon(True)123456789101112131415161718192021import threadingimport time# 测试主线程是否会等待子线程执行完成以后程序再退出def show_info(): for i in range(5): print(&quot;test:&quot;, i) time.sleep(0.5)if __name__ == '__main__': # 创建子线程守护主线程 # daemon=True 守护主线程 # 守护主线程方式1 sub_thread = threading.Thread(target=show_info, daemon=True) # 设置成为守护主线程，主线程退出后子线程直接销毁不再执行子线程的代码 # 守护主线程方式2 # sub_thread.setDaemon(True) sub_thread.start() # 主线程延时1秒 time.sleep(1) print(&quot;over&quot;) test: 0test: 1over 线程之间共享全局变量 需求: 定义一个列表类型的全局变量创建两个子线程分别执行向全局变量添加数据的任务和向全局变量读取数据的任务查看线程之间是否共享全局变量数据 123456789101112131415161718192021222324252627import threadingimport time# 定义全局变量my_list = list()# 写入数据任务def write_data(): for i in range(5): my_list.append(i) time.sleep(0.1) print(&quot;write_data:&quot;, my_list)# 读取数据任务def read_data(): print(&quot;read_data:&quot;, my_list)if __name__ == '__main__': # 创建写入数据的线程 write_thread = threading.Thread(target=write_data) # 创建读取数据的线程 read_thread = threading.Thread(target=read_data) write_thread.start() # 延时 # time.sleep(1) # 主线程等待写入线程执行完成以后代码在继续往下执行 write_thread.join() print(&quot;开始读取数据啦&quot;) read_thread.start() write_data: [0, 1, 2, 3, 4]开始读取数据啦read_data: [0, 1, 2, 3, 4] 线程之间共享全局变量数据出现错误问题需求: 定义两个函数，实现循环100万次，每循环一次给全局变量加1 创建两个子线程执行对应的两个函数，查看计算后的结果12345678910111213141516171819202122232425import threading# 定义全局变量g_num = 0# 循环一次给全局变量加1def sum_num1(): for i in range(1000000): global g_num g_num += 1 print(&quot;sum1:&quot;, g_num)# 循环一次给全局变量加1def sum_num2(): for i in range(1000000): global g_num g_num += 1 print(&quot;sum2:&quot;, g_num)if __name__ == '__main__': # 创建两个线程 first_thread = threading.Thread(target=sum_num1) second_thread = threading.Thread(target=sum_num2) # 启动线程 first_thread.start() # 启动线程 second_thread.start() sum1: 1210949sum2: 1496035 多线程同时对全局变量操作数据发生了错误,错误分析: 两个线程first_thread和second_thread都要对全局变量g_num(默认是0)进行加1运算，但是由于是多线程同时操作，有可能出现下面情况： 在g_num=0时，first_thread取得g_num=0。此时系统把first_thread调度为”sleeping”状态，把second_thread转换为”running”状态，t2也获得g_num=0 然后second_thread对得到的值进行加1并赋给g_num，使得g_num=1 然后系统又把second_thread调度为”sleeping”，把first_thread转为”running”。线程t1又把它之前得到的0加1后赋值给g_num。 这样导致虽然first_thread和first_thread都对g_num加1，但结果仍然是g_num=1全局变量数据错误的解决办法: 线程同步: 保证同一时刻只能有一个线程去操作全局变量 同步: 就是协同步调，按预定的先后次序进行运行。如:你说完，我再说, 好比现实生活中的对讲机 线程同步的方式: 线程等待(join) 互斥锁12345678910111213141516171819202122232425262728import threading# 定义全局变量g_num = 0# 循环1000000次每次给全局变量加1def sum_num1(): for i in range(1000000): global g_num g_num += 1 print(&quot;sum1:&quot;, g_num)# 循环1000000次每次给全局变量加1def sum_num2(): for i in range(1000000): global g_num g_num += 1 print(&quot;sum2:&quot;, g_num)if __name__ == '__main__': # 创建两个线程 first_thread = threading.Thread(target=sum_num1) second_thread = threading.Thread(target=sum_num2) # 启动线程 first_thread.start() # 主线程等待第一个线程执行完成以后代码再继续执行，让其执行第二个线程 # 线程同步： 一个任务执行完成以后另外一个任务才能执行，同一个时刻只有一个任务在执行 first_thread.join() # 启动线程 second_thread.start() sum1: 1000000sum2: 2000000 互斥锁互斥锁: 对共享数据进行锁定，保证同一时刻只能有一个线程去操作。注意:互斥锁是多个线程一起去抢，抢到锁的线程先执行，没有抢到锁的线程需要等待，等互斥锁使用完释放后，其它等待的线程再去抢这个锁。互斥锁的使用互斥锁使用步骤:1234567# 创建锁mutex = threading.Lock()# 上锁mutex.acquire()...这里编写代码能保证同一时刻只能有一个线程去操作, 对共享数据进行锁定...# 释放锁mutex.release() 注意点:acquire和release方法之间的代码同一时刻只能有一个线程去操作如果在调用acquire方法的时候 其他线程已经使用了这个互斥锁，那么此时acquire方法会堵塞，直到这个互斥锁释放后才能再次上锁。使用互斥锁完成2个线程对同一个全局变量各加100万次的操作123456789101112131415161718192021222324252627282930313233343536import threading# 定义全局变量g_num = 0# 创建全局互斥锁lock = threading.Lock()# 循环一次给全局变量加1def sum_num1(): # 上锁 lock.acquire() for i in range(1000000): global g_num g_num += 1 print(&quot;sum1:&quot;, g_num) # 释放锁 lock.release()# 循环一次给全局变量加1def sum_num2(): # 上锁 lock.acquire() for i in range(1000000): global g_num g_num += 1 print(&quot;sum2:&quot;, g_num) # 释放锁 lock.release()if __name__ == '__main__': # 创建两个线程 first_thread = threading.Thread(target=sum_num1) second_thread = threading.Thread(target=sum_num2) # 启动线程 first_thread.start() second_thread.start() # 提示：加上互斥锁，那个线程抢到这个锁我们决定不了，那线程抢到锁那个线程先执行，没有抢到的线程需要等待 # 加上互斥锁多任务瞬间变成单任务，性能会下降，也就是说同一时刻只能有一个线程去执行 sum1: 1000000sum2: 2000000 说明:通过执行结果可以地址互斥锁能够保证多个线程访问共享数据不会出现数据错误问题 死锁:死锁: 一直等待对方释放锁的情景就是死锁 死锁示例需求:根据下标在列表中取值, 保证同一时刻只能有一个线程去取值 1234567891011121314151617181920212223242526import threadingimport time# 创建互斥锁lock = threading.Lock()# 根据下标去取值， 保证同一时刻只能有一个线程去取值def get_value(index): # 上锁 lock.acquire() print(threading.current_thread()) my_list = [3,6,8,1] # 判断下标释放越界 if index &gt;= len(my_list): print(&quot;下标越界:&quot;, index) return value = my_list[index] print(value) time.sleep(0.2) # 释放锁 lock.release()if __name__ == '__main__': # 模拟大量线程去执行取值操作 for i in range(30): sub_thread = threading.Thread(target=get_value, args=(i,)) sub_thread.start() 避免死锁==在合适的地方释放锁- 123456789101112131415161718192021222324252627import threadingimport time# 创建互斥锁lock = threading.Lock()# 根据下标去取值， 保证同一时刻只能有一个线程去取值def get_value(index): # 上锁 lock.acquire() print(threading.current_thread()) my_list = [3,6,8,1] if index &gt;= len(my_list): print(&quot;下标越界:&quot;, index) # 当下标越界需要释放锁，让后面的线程还可以取值 lock.release() return value = my_list[index] print(value) time.sleep(0.2) # 释放锁 lock.release()if __name__ == '__main__': # 模拟大量线程去执行取值操作 for i in range(30): sub_thread = threading.Thread(target=get_value, args=(i,)) sub_thread.start() 进程和线程的对比的三个方向 ==关系对比== 线程是依附在进程里面的，没有进程就没有线程。 一个进程默认提供一条线程，进程可以创建多个线程。 ==区别对比== 进程之间不共享全局变量， 线程之间共享全局变量，但是要注意资源竞争的问题，解决办法: 互斥锁或者线程同步 创建进程的资源开销要比创建线程的资源开销要大 进程是操作系统资源分配的基本单位，线程是CPU调度的基本单位 线程不能够独立执行，必须依存在进程中 多进程开发比单进程多线程开发稳定性要强 ==优缺点对比== 进程优缺点: 优点：可以用多核 缺点：资源开销大 线程优缺点: 优点：资源开销小 缺点：不能使用多核网络编程socket 的概念socket (简称 套接字) 是进程之间通信一个工具，好比现实生活中的插座，所有的家用电器要想工作都是基于插座进行，进程之间想要进行网络通信需要基于这个 socket。 socket 的作用：负责进程之间的网络数据传输，好比数据的搬运工。 socket 使用场景：不夸张的说，只要跟网络相关的应用程序或者软件都使用到了 socket 。 TCP 网络应用程序开发流程TCP 网络应用程序开发流程的介绍TCP 网络应用程序开发分为: TCP 客户端程序开发 TCP 服务端程序开发 说明:客户端程序是指运行在用户设备上的程序 服务端程序是指运行在服务器设备上的程序，专门为客户端提供数据服务。 TCP 客户端程序开发流程的介绍步骤说明: 创建客户端套接字对象 和服务端套接字建立连接 发送数据 接收数据 关闭客户端套接字TCP 客户端程序开发导入 socket 模块 import socket创建客户端 socket 对象 socket.socket(AddressFamily, Type)==参数说明:== AddressFamily 表示IP地址类型, 分为TPv4和IPv6 Type 表示传输协议类型==方法说明:== connect((host, port)) 表示和服务端套接字建立连接, host是服务器ip地址，port是应用程序的端口号 send(data) 表示发送数据，data是二进制数据 recv(buffersize) 表示接收数据, buffersize是每次接收数据的长度1234567891011121314151617181920212223import socketif __name__ == '__main__': # 创建tcp客户端套接字 # 1. AF_INET：表示ipv4 # 2. SOCK_STREAM: tcp传输协议 tcp_client_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) # 和服务端应用程序建立连接 tcp_client_socket.connect((&quot;192.168.131.62&quot;, 8080)) # 代码执行到此，说明连接建立成功 # 准备发送的数据 send_data = &quot;你好服务端，我是客户端小黑!&quot;.encode(&quot;gbk&quot;) # 发送数据 tcp_client_socket.send(send_data) # 接收数据, 这次接收的数据最大字节数是1024 recv_data = tcp_client_socket.recv(1024) # 返回的直接是服务端程序发送的二进制数据 print(recv_data) # 对数据进行解码 recv_content = recv_data.decode(&quot;gbk&quot;) print(&quot;接收服务端的数据为:&quot;, recv_content) # 关闭套接字 tcp_client_socket.close() b’hello’接收服务端的数据为: hello TCP 服务端程序开发流程的介绍步骤说明: 创建服务端端套接字对象 绑定端口号 设置监听 等待接受客户端的连接请求 接收数据 发送数据 关闭套接字 TCP服务端程序开发导入 socket 模块 import socket创建服务端 socket 对象 socket.socket(AddressFamily, Type)==参数说明:== AddressFamily 表示IP地址类型, 分为TPv4和IPv6 Type 表示传输协议类型==方法说明:== bind((host, port)) 表示绑定端口号, host 是 ip 地址，port 是端口号，ip 地址一般不指定，表示本机的任何一个ip地址都可以。 listen (backlog) 表示设置监听，backlog参数表示最大等待建立连接的个数。 accept() 表示等待接受客户端的连接请求 send(data) 表示发送数据，data 是二进制数据 crecv(buffersize) 表示接收数据, buffersize 是每次接收数据的长度123456789101112131415161718192021222324252627282930313233343536import socketif __name__ == '__main__': # 创建tcp服务端套接字 tcp_server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) # 设置端口号复用，让程序退出端口号立即释放 tcp_server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, True) # 给程序绑定端口号 tcp_server_socket.bind((&quot;&quot;, 8989)) # 设置监听 # 128:最大等待建立连接的个数， 提示： 目前是单任务的服务端，同一时刻只能服务与一个客户端，后续使用多任务能够让服务端同时服务与多个客户端， # 不需要让客户端进行等待建立连接 # listen后的这个套接字只负责接收客户端连接请求，不能收发消息，收发消息使用返回的这个新套接字来完成 tcp_server_socket.listen(128) # 等待客户端建立连接的请求, 只有客户端和服务端建立连接成功代码才会解阻塞，代码才能继续往下执行 # 1. 专门和客户端通信的套接字： service_client_socket # 2. 客户端的ip地址和端口号： ip_port service_client_socket, ip_port = tcp_server_socket.accept() # 代码执行到此说明连接建立成功 print(&quot;客户端的ip地址和端口号:&quot;, ip_port) # 接收客户端发送的数据, 这次接收数据的最大字节数是1024 recv_data = service_client_socket.recv(1024) # 获取数据的长度 recv_data_length = len(recv_data) print(&quot;接收数据的长度为:&quot;, recv_data_length) # 对二进制数据进行解码 recv_content = recv_data.decode(&quot;gbk&quot;) print(&quot;接收客户端的数据为:&quot;, recv_content) # 准备发送的数据 send_data = &quot;ok, 问题正在处理中...&quot;.encode(&quot;gbk&quot;) # 发送数据给客户端 service_client_socket.send(send_data) # 关闭服务与客户端的套接字， 终止和客户端通信的服务 service_client_socket.close() # 关闭服务端的套接字, 终止和客户端提供建立连接请求的服务 tcp_server_socket.close() 客户端的ip地址和端口号: (‘172.16.47.209’, 52472)接收数据的长度为: 5接收客户端的数据为: hello 说明:当客户端和服务端建立连接后，服务端程序退出后端口号不会立即释放，需要等待大概1-2分钟。解决办法有两种: 更换服务端端口号 设置端口号复用(推荐大家使用)，也就是说让服务端程序退出后端口号立即释放。设置端口号复用的代码如下:1234# 参数1: 表示当前套接字# 参数2: 设置端口号复用选项# 参数3: 设置端口号复用选项对应的值tcp_server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, True) TCP网络应用程序的注意点 当 TCP 客户端程序想要和 TCP 服务端程序进行通信的时候必须要先建立连接 TCP 客户端程序一般不需要绑定端口号，因为客户端是主动发起建立连接的。 TCP 服务端程序必须绑定端口号，否则客户端找不到这个 TCP 服务端程序。 listen 后的套接字是被动套接字，只负责接收新的客户端的连接请求，不能收发消息。 当 TCP 客户端程序和 TCP 服务端程序连接成功后， TCP 服务器端程序会产生一个新的套接字，收发客户端消息使用该套接字。 关闭 accept 返回的套接字意味着和这个客户端已经通信完毕。 关闭 listen 后的套接字意味着服务端的套接字关闭了，会导致新的客户端不能连接服务端，但是之前已经接成功的客户端还能正常通信。 当客户端的套接字调用 close 后，服务器端的 recv 会解阻塞，返回的数据长度为0，服务端可以通过返回数据的长度来判断客户端是否已+ 经下线，反之服务端关闭套接字，客户端的 recv 也会解阻塞，返回的数据长度也为0。 案例-多任务版TCP服务端程序开发具体实现步骤 编写一个TCP服务端程序，循环等待接受客户端的连接请求 当客户端和服务端建立连接成功，创建子线程，使用子线程专门处理客户端的请求，防止主线程阻塞 把创建的子线程设置成为守护主线程，防止主线程无法退出。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748import socketimport threading# 处理客户端的请求操作def handle_client_request(service_client_socket, ip_port): # 循环接收客户端发送的数据 while True: # 接收客户端发送的数据 recv_data = service_client_socket.recv(1024) # 容器类型判断是否有数据可以直接使用if语句进行判断，如果容器类型里面有数据表示条件成立，否则条件失败 # 容器类型: 列表、字典、元组、字符串、set、range、二进制数据 if recv_data: print(recv_data.decode(&quot;gbk&quot;), ip_port) # 回复 service_client_socket.send(&quot;ok，问题正在处理中...&quot;.encode(&quot;gbk&quot;)) else: print(&quot;客户端下线了:&quot;, ip_port) break # 终止和客户端进行通信 service_client_socket.close()if __name__ == '__main__': # 创建tcp服务端套接字 tcp_server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) # 设置端口号复用，让程序退出端口号立即释放 tcp_server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, True) # 绑定端口号 tcp_server_socket.bind((&quot;&quot;, 9090)) # 设置监听, listen后的套接字是被动套接字，只负责接收客户端的连接请求 tcp_server_socket.listen(128) # 循环等待接收客户端的连接请求 while True: # 等待接收客户端的连接请求 service_client_socket, ip_port = tcp_server_socket.accept() print(&quot;客户端连接成功:&quot;, ip_port) # 当客户端和服务端建立连接成功以后，需要创建一个子线程，不同子线程负责接收不同客户端的消息 sub_thread = threading.Thread(target=handle_client_request, args=(service_client_socket, ip_port)) # 设置守护主线程 sub_thread.setDaemon(True) # 启动子线程 sub_thread.start() # tcp服务端套接字可以不需要关闭，因为服务端程序需要一直运行 # tcp_server_socket.close() 客户端连接成功: (‘172.16.47.209’, 51528)客户端连接成功: (‘172.16.47.209’, 51714)hello1 (‘172.16.47.209’, 51528)hello2 (‘172.16.47.209’, 51714) socket之send和recv原理剖析1. 认识TCP socket的发送和接收缓冲区当创建一个TCP socket对象的时候会有一个发送缓冲区和一个接收缓冲区，这个发送和接收缓冲区指的就是内存中的一片空间。 2. send原理剖析send是不是直接把数据发给服务端?不是，要想发数据，必须得通过网卡发送数据，应用程序是无法直接通过网卡发送数据的，它需要调用操作系统接口，也就是说，应用程序把发送的数据先写入到发送缓冲区(内存中的一片空间)，再由操作系统控制网卡把发送缓冲区的数据发送给服务端网卡 。 3. recv原理剖析recv是不是直接从客户端接收数据?不是，应用软件是无法直接通过网卡接收数据的，它需要调用操作系统接口，由操作系统通过网卡接收数据，把接收的数据写入到接收缓冲区(内存中的一片空间），应用程序再从接收缓存区获取客户端发送的数据。 send和recv原理剖析图说明: 发送数据是发送到发送缓冲区 接收数据是从接收缓冲区 获取 Python静态Web服务器搭建Python自带静态Web服务器如何搭建Python自带的静态Web服务器搭建Python自带的静态Web服务器使用 python3 -m http.server 端口号, 端口号不指定默认是8000访问搭建的静态Web服务器 IP:端口 返回固定页面数据开发自己的静态Web服务器实现步骤: 编写一个TCP服务端程序1234tcp_server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)# 循环接受客户端的连接请求while True: conn_socket, ip_port = tcp_server_socket.accept() 获取浏览器发送的http请求报文数据1client_request_data = conn_socket.recv(4096) 读取固定页面数据，把页面数据组装成HTTP响应报文数据发送给浏览器。12response_data = (response_line + response_header + &quot;
