&quot;).encode(&quot;utf-8&quot;) + response_body # 发送数据 new_socket.send(response_data) finally: # 关闭服务与客户端的套接字 new_socket.close() # 启动web服务器进行工作 def start(self): while True: # 等待接受客户端的连接请求 new_socket, ip_port = self.tcp_server_socket.accept() # 当客户端和服务器建立连接程，创建子线程 sub_thread = threading.Thread(target=self.handle_client_request, args=(new_socket,)) # 设置守护主线程 sub_thread.setDaemon(True) # 启动子线程执行对应的任务 sub_thread.start()# 程序入口函数def main(): print(sys.argv) # 判断命令行参数是否等于2, if len(sys.argv) != 2: print(&quot;执行命令如下: python3 xxx.py 8000&quot;) return # 判断字符串是否都是数字组成 if not sys.argv[1].isdigit(): print(&quot;执行命令如下: python3 xxx.py 8000&quot;) return # 获取终端命令行参数 port = int(sys.argv[1]) # 创建web服务器对象 web_server = HttpWebServer(port) # 启动web服务器进行工作 web_server.start()if __name__ == '__main__': main() Python程序操作MySQL数据库安装pymysql第三方包: 12[root@liruilong ~]# yum -y install pymysql[root@liruilong ~]# ls pymysql的使用: 导入 pymysql 包 : import pymysql 创建连接对象:调用pymysql模块中的connect()函数来创建连接对象conn=connect(参数列表) 参数host：连接的mysql主机，如果本机是’localhost’ 参数port：连接的mysql主机的端口，默认是3306 参数user：连接的用户名 参数password：连接的密码 参数database：数据库的名称 参数charset：通信采用的编码方式，推荐使用utf8连接对象操作说明: 关闭连接 conn.close() 提交数据 conn.commit() 撤销数据 conn.rollback() 获取游标对象：获取游标对象的目标就是要执行sql语句，完成对数据库的增、删、改、查操作。 12# 调用连接对象的cursor()方法获取游标对象 cur =conn.cursor() 游标操作说明: 使用游标执行SQL语句: execute(operation [parameters ]) 执行SQL语句，返回受影响的行数，主要用于执行insert、update、delete、select等语句 获取查询结果集中的一条数据:cur.fetchone()返回一个元组, 如 (1,’张三’) 获取查询结果集中的所有数据: cur.fetchall()返回一个元组,如((1,’张三’),(2,’李四’)) 关闭游标: cur.close(),表示和数据库操作完成 pymysql完成数据的查询操作1234567891011121314151617181920212223242526import pymysql# 创建连接对象conn = pymysql.connect(host='localhost', port=3306, user='root', password='mysql',database='python', charset='utf8')# 获取游标对象cursor = conn.cursor()# 查询 SQL 语句sql = &quot;select * from students;&quot;# 执行 SQL 语句 返回值就是 SQL 语句在执行过程中影响的行数row_count = cursor.execute(sql)print(&quot;SQL 语句执行影响的行数%d&quot; % row_count)# 取出结果集中一行数据, 例如:(1, '张三')# print(cursor.fetchone())# 取出结果集中的所有数据, 例如:((1, '张三'), (2, '李四'), (3, '王五'))for line in cursor.fetchall(): print(line)# 关闭游标cursor.close()# 关闭连接conn.close() pymysql完成对数据的增删改1234567891011121314151617181920212223242526272829import pymysql# 创建连接对象conn = pymysql.connect(host='localhost', port=3306, user='root', password='mysql',database='python', charset='utf8')# 获取游标对象cursor = conn.cursor()try: # 添加 SQL 语句 # sql = &quot;insert into students(name) values('刘璐'), ('王美丽');&quot; # 删除 SQ L语句 # sql = &quot;delete from students where id = 5;&quot; # 修改 SQL 语句 sql = &quot;update students set name = '王铁蛋' where id = 6;&quot; # 执行 SQL 语句 row_count = cursor.execute(sql) print(&quot;SQL 语句执行影响的行数%d&quot; % row_count) # 提交数据到数据库 conn.commit()except Exception as e: # 回滚数据， 即撤销刚刚的SQL语句操作 conn.rollback()# 关闭游标cursor.close()# 关闭连接conn.close() conn.commit() 表示将修改操作提交到数据库 conn.rollback() 表示回滚数据 防止SQL注入什么是SQL注入?用户提交带有恶意的数据与SQL语句进行字符串方式的拼接，从而影响了SQL语句的语义，最终产生数据泄露的现象。 ·如何防止SQL注入?SQL语句参数化 SQL语言中的参数使用%s来占位，此处不是python中的字符串格式化操作,将SQL语句中%s占位所需要的参数存在一个列表中，把参数列表传递给execute方法中第二个参数防止SQL注入的示例代码: 123456789101112131415161718192021222324252627282930313233343536373839404142from pymysql import connectdef main(): find_name = input(&quot;请输入物品名称：&quot;) # 创建Connection连接 conn = connect(host='localhost',port=3306,user='root',password='mysql',database='jing_dong',charset='utf8') # 获得Cursor对象 cs1 = conn.cursor() # 非安全的方式 # 输入 ' or 1 = 1 or ' (单引号也要输入) # sql = &quot;select * from goods where name='%s'&quot; % find_name # print(&quot;&quot;&quot;sql===&gt;%s&lt;====&quot;&quot;&quot; % sql) # # 执行select语句，并返回受影响的行数：查询所有数据 # count = cs1.execute(sql) # 安全的方式 # 构造参数列表 params = [find_name] # 执行select语句，并返回受影响的行数：查询所有数据 count = cs1.execute(&quot;select * from goods where name=%s&quot;, params) # 注意： # 如果要是有多个参数，需要进行参数化 # 那么params = [数值1, 数值2....]，此时sql语句中有多个%s即可 # %s 不需要带引号 # 打印受影响的行数 print(count) # 获取查询的结果 # result = cs1.fetchone() result = cs1.fetchall() # 打印查询的结果 print(result) # 关闭Cursor对象 cs1.close() # 关闭Connection对象 conn.close()if __name__ == '__main__': main() 事务的介绍事务就是用户定义的一系列执行SQL语句的操作, 这些操作要么完全地执行，要么完全地都不执行， 它是一个不可分割的工作执行单元。 事务的使用场景:在日常生活中，有时我们需要进行银行转账，这个银行转账操作背后就是需要执行多个SQL语句，假如这些SQL执行到一半突然停电了，那么就会导致这个功能只完成了一半，这种情况是不允许出现，要想解决这个问题就需要通过事务来完成。 事务的四大特性 原子性Atomicity:一个事务必须被视为一个不可分割的最小工作单元，整个事务中的所有操作要么全部提交成功，要么全部失败回滚，对于一个事务来说，不可能只执行其中的一部分操作，这就是事务的原子性 一致性Consistency:数据库总是从一个一致性的状态转换到另一个一致性的状态。（在前面的例子中，一致性确保了，即使在转账过程中系统崩溃，支票账户中也不会损失200美元，因为事务最终没有提交，所以事务中所做的修改也不会保存到数据库中。） 隔离性Isolation:通常来说，一个事务所做的修改操作在提交事务之前，对于其他事务来说是不可见的。（在前面的例子中，当执行完第三条语句、第四条语句还未开始时，此时有另外的一个账户汇总程序开始运行，则其看到支票帐户的余额并没有被减去200美元。） 持久性Durability:一旦事务提交，则其所做的修改会永久保存到数据库。 事务的使用： 在使用事务之前，先要确保表的存储引擎是 InnoDB 类型, 只有这个类型才可以使用事务，MySQL数据库中表的存储引擎默认是 InnoDB 类型。 表的存储引擎说明:表的存储引擎就是提供存储数据一种机制，不同表的存储引擎提供不同的存储机制。 开启事务后执行修改命令，变更数据会保存到MySQL服务端的缓存文件中，而不维护到物理表中 MySQL数据库默认采用自动提交(autocommit)模式，如果没有显示的开启一个事务,那么每条sql语句都会被当作一个事务执行提交的操作当设置autocommit=0就是取消了自动提交事务模式，直到显示的执行commit和rollback表示该事务结束。 set autocommit = 0 表示取消自动提交事务模式，需要手动执行commit完成事务的提交 索引索引的介绍索引在MySQL中也叫做“键”，它是一个特殊的文件，它保存着数据表里所有记录的位置信息，更通俗的来说，数据库索引好比是一本书前面的目录，能加快数据库的查询速度。 应用场景:当数据库中数据量很大时，查找数据会变得很慢，我们就可以通过索引来提高数据库的查询效率。 索引的使用 查看表中已有索引: show index from 表名; 主键列会自动创建索引 索引名不指定，默认使用字段名验证索引性能操作：123456789101112-- 开启运行时间监测：set profiling=1;-- 查找第1万条数据ha-99999select * from test_index where title='ha-99999';-- 查看执行的时间：show profiles;-- 给title字段创建索引：alter table test_index add index (title);-- 再次执行查询语句select * from test_index where title='ha-99999';-- 再次查看执行的时间show profiles; 联合索引联合索引又叫复合索引，即一个索引覆盖表中两个或者多个字段，一般用在多个字段一起查询的时候。12345678910-- 创建teacher表create table teacher( id int not null primary key auto_increment, name varchar(10), age int);-- 创建联合索引alter table teacher add index (name,age); 联合索引的好处:减少磁盘空间开销，因为每创建一个索引，其实就是创建了一个索引文件，那么会增加磁盘空间的开销。 联合索引的最左原则在使用联合索引的时候，我们要遵守一个最左原则,即index(name,age)支持 name 、name 和 age 组合查询,而不支持单独 age 查询，因为没有用到创建的联合索引。最左原则示例: 12345-- 下面的查询使用到了联合索引select * from stu where name='张三' -- 这里使用了联合索引的name部分select * from stu where name='李四' and age=10 -- 这里完整的使用联合索引，包括 name 和 age 部分 -- 下面的查询没有使用到联合索引select * from stu where age=10 -- 因为联合索引里面没有这个组合，只有 name | name age 这两种组合 在使用联合索引的查询数据时候一定要保证联合索引的最左侧字段出现在查询条件里面，否则联合索引失效 MySQL中索引的优点和缺点和使用原则 优点：. ==加快数据的查询速度== 缺点：. ==创建索引会耗费时间和占用磁盘空间，并且随着数据量的增加所耗费的时间也会增加== 使用原则： 通过优缺点对比，不是索引越多越好，而是需要自己合理的使用。 对经常更新的表就避免对其进行过多索引的创建，对经常用于查询的字段应该创建索引， 数据量小的表最好不要使用索引，因为由于数据较少，可能查询全部数据花费的时间比遍历索引的时间还要短，索引就可能不会产生优化效+ 果。 在一字段上相同值比较多不要建立索引，比如在学生表的”性别”字段上只有男，女两个不同值。相反的，在一个字段上不同值较多可是建立索引。 闭包&amp;装饰器闭包的介绍:我们前面已经学过了函数，我们知道当函数调用完，函数内定义的变量都销毁了，但是我们有时候需要保存函数内的这个变量，每次在这个变量的基础上完成一些列的操作，比如: 每次在这个变量的基础上和其它数字进行求和计算，那怎么办呢?我们就可以通过咱们今天学习的闭包来解决这个需求。闭包的定义:在函数嵌套的前提下，内部函数使用了外部函数的变量，并且外部函数返回了内部函数，我们把这个使用外部函数变量的内部函数称为闭包。 闭包的构成条件通过闭包的定义，我们可以得知闭包的形成条件: 在函数嵌套(函数里面再定义函数)的前提下 内部函数使用了外部函数的变量(还包括外部函数的参数) 外部函数返回了内部函数123456789101112131415# 定义一个外部函数def func_out(num1): # 定义一个内部函数 def func_inner(num2): # 内部函数使用了外部函数的变量(num1) result = num1 + num2 print(&quot;结果是:&quot;, result) # 外部函数返回了内部函数，这里返回的内部函数就是闭包 return func_inner# 创建闭包实例 f = func_out(1)# 执行闭包f(2)f(3) 结果是: 3结果是: 4 闭包执行结果的说明:通过上面的输出结果可以看出闭包保存了外部函数内的变量num1，每次执行闭包都是在num1 = 1 基础上进行计算。 闭包的作用闭包可以保存外部函数内的变量，不会随着外部函数调用完而销毁。注意点:由于闭包引用了外部函数的变量，则外部函数的变量没有及时释放，消耗内存。 闭包的使用案例 需求: 根据配置信息使用闭包实现不同人的对话信息，例如对话:张三: 到北京了吗? 李四: 已经到了，放心吧。 定义外部函数接收不同的配置信息参数，参数是人名 定义内部函数接收对话信息参数 在内部函数里面把配置信息和对话信息进行拼接输出功能代码的实现12345678910111213141516# 外部函数def config_name(name): # 内部函数 def say_info(info): print(name + &quot;: &quot; + info) return say_infotom = config_name(&quot;Tom&quot;)tom(&quot;你好!&quot;)tom(&quot;你好, 在吗?&quot;)jerry = config_name(&quot;jerry&quot;)jerry(&quot;不在, 不和玩!&quot;) 运行结果:Tom: 你好!Tom: 你好, 在吗?jerry: 不在, 不和玩! 闭包案例说明:闭包还可以提高代码的可重用性，不需要再手动定义额外的功能函数。 修改闭包内使用的外部变量修改闭包内使用的外部变量的错误示例: 12345678910111213141516171819202122# 定义一个外部函数def func_out(num1): # 定义一个内部函数 def func_inner(num2): # 这里本意想要修改外部num1的值，实际上是在内部函数定义了一个局部变量num1 num1 = 10 # 内部函数使用了外部函数的变量(num1) result = num1 + num2 print(&quot;结果是:&quot;, result) print(num1) func_inner(1) print(num1) # 外部函数返回了内部函数，这里返回的内部函数就是闭包 return func_inner# 创建闭包实例f = func_out(1)# 执行闭包f(2) 装饰器 装饰器的定义:就是给已有函数增加额外功能的函数，它本质上就是一个闭包函数。类似于AOP环绕通知的逆向应用装饰器的功能特点: 不修改已有函数的源代码 不修改已有函数的调用方式 给已有函数增加额外的功能 12345678910111213141516171819202122# 添加一个登录验证的功能def check(fn): def inner(): print(&quot;请先登录....&quot;) fn() return innerdef comment(): print(&quot;发表评论&quot;)# 使用装饰器来装饰函数comment = check(comment)comment()# 装饰器的基本雏形# def decorator(fn): # fn:目标函数.# def inner():# '''执行函数之前'''# fn() # 执行被装饰的函数# '''执行函数之后'''# return inner 执行结果:请先登录….发表评论 闭包函数有且只有一个参数，必须是函数类型，这样定义的函数才是装饰器。 写代码要遵循开放封闭原则，它规定已经实现的功能代码不允许被修改，但可以被扩展。 装饰器的语法糖写法如果有多个函数都需要添加登录验证的功能，每次都需要编写func = check(func)这样代码对已有函数进行装饰，这种做法还是比较麻烦。 Python给提供了一个装饰函数更加简单的写法，那就是语法糖，语法糖的书写格式是: @装饰器名字，通过语法糖的方式也可以完成对已有函数的装饰. 1234567891011121314# 添加一个登录验证的功能def check(fn): print(&quot;装饰器函数执行了&quot;) def inner(): print(&quot;请先登录....&quot;) fn() return inner# 使用语法糖方式来装饰函数@checkdef comment(): print(&quot;发表评论&quot;)comment() 装饰器的使用装饰器的使用场景 函数执行时间的统计 输出日志信息 装饰器实现已有函数执行时间的统计 123456789101112131415161718import time# 装饰器函数def get_time(func): def inner(): begin = time.time() func() end = time.time() print(&quot;函数执行花费%f&quot; % (end-begin)) return inner@get_timedef func1(): for i in range(100000): print(i)func1() …9999599996999979999899999函数执行花费0.329066 通用装饰器的使用装饰带有参数的函数123456789101112131415# 添加输出日志的功能def logging(fn): def inner(num1, num2): print(&quot;--正在努力计算--&quot;) fn(num1, num2) return inner# 使用装饰器装饰函数@loggingdef sum_num(a, b): result = a + b print(result)sum_num(1, 2) –正在努力计算–3 装饰带有返回值的函数123456789101112131415161718# 添加输出日志的功能def logging(fn): def inner(num1, num2): print(&quot;--正在努力计算--&quot;) result = fn(num1, num2) return result return inner# 使用装饰器装饰函数@loggingdef sum_num(a, b): result = a + b return resultresult = sum_num(1, 2)print(result) –正在努力计算–3 装饰带有不定长参数的函数12345678910111213141516171819202122# 添加输出日志的功能def logging(fn): def inner(*args, **kwargs): print(&quot;--正在努力计算--&quot;) fn(*args, **kwargs) return inner# 使用语法糖装饰函数@loggingdef sum_num(*args, **kwargs): result = 0 for value in args: result += value for value in kwargs.values(): result += value print(result)sum_num(1, 2, a=10) –正在努力计算–13 通用装饰器12345678910111213141516171819202122232425262728293031# 添加输出日志的功能def logging(fn): def inner(*args, **kwargs): print(&quot;--正在努力计算--&quot;) result = fn(*args, **kwargs) return result return inner# 使用语法糖装饰函数@loggingdef sum_num(*args, **kwargs): result = 0 for value in args: result += value for value in kwargs.values(): result += value return result@loggingdef subtraction(a, b): result = a - b print(result)result = sum_num(1, 2, a=10)print(result)subtraction(4, 2) –正在努力计算–13–正在努力计算–2 多个装饰器的使用多个装饰器的装饰过程是: 离函数最近的装饰器先装饰，然后外面的装饰器再进行装饰，由内到外的装饰过程 1234567891011121314151617181920212223242526def make_div(func): &quot;&quot;&quot;对被装饰的函数的返回值 div标签&quot;&quot;&quot; def inner(*args, **kwargs): return &quot;&lt;div&gt;&quot; + func() + &quot;&lt;/div&gt;&quot; return innerdef make_p(func): &quot;&quot;&quot;对被装饰的函数的返回值 p标签&quot;&quot;&quot; def inner(*args, **kwargs): return &quot;&lt;p&gt;&quot; + func() + &quot;&lt;/p&gt;&quot; return inner# 装饰过程: # 1 content = make_p(content) # 2 content = make_div(content)# content = make_div(make_p(content))@make_div@make_pdef content(): return &quot;人生苦短&quot;result = content()print(result) 带有参数的装饰器带有参数的装饰器就是使用装饰器装饰函数的时候可以传入指定参数，语法格式: @装饰器(参数,...)错误写法:==装饰器只能接收一个参数，并且还是函数类型。== 123456789101112131415161718def decorator(fn, flag): def inner(num1, num2): if flag == &quot;+&quot;: print(&quot;--正在努力加法计算--&quot;) elif flag == &quot;-&quot;: print(&quot;--正在努力减法计算--&quot;) result = fn(num1, num2) return result return inner@decorator('+')def add(a, b): result = a + b return resultresult = add(1, 3)print(result) Traceback (most recent call last): File “/home/python/Desktop/test/hho.py”, line 12, in @decorator(‘+’)TypeError: decorator() missing 1 required positional argument: ‘flag’ 正确写法:==在装饰器外面再包裹上一个函数，让最外面的函数接收参数，返回的是装饰器，因为@符号后面必须是装饰器实例。==在装饰器外面再包裹上一个函数，让最外面的函数接收参数，返回的是装饰器，因为@符号后面必须是装饰器实例。 12345678910111213141516171819202122232425262728293031323334# 添加输出日志的功能def logging(flag): def decorator(fn): def inner(num1, num2): if flag == &quot;+&quot;: print(&quot;--正在努力加法计算--&quot;) elif flag == &quot;-&quot;: print(&quot;--正在努力减法计算--&quot;) result = fn(num1, num2) return result return inner # 返回装饰器 return decorator# 使用装饰器装饰函数@logging(&quot;+&quot;)def add(a, b): result = a + b return result@logging(&quot;-&quot;)def sub(a, b): result = a - b return resultresult = add(1, 2)print(result)result = sub(1, 2)print(result) 类装饰器的使用装饰器还有一种特殊的用法就是类装饰器，就是通过定义一个类来装饰函数。 123456789101112131415class Check(object): def __init__(self, fn): # 初始化操作在此完成 self.__fn = fn # 实现__call__方法，表示对象是一个可调用对象，可以像调用函数一样进行调用。 def __call__(self, *args, **kwargs): # 添加装饰功能 print(&quot;请先登陆...&quot;) self.__fn()@Checkdef comment(): print(&quot;发表评论&quot;)comment() @Check 等价于 comment = Check(comment), 所以需要提供一个init方法，并多增加一个fn参数。 要想类的实例对象能够像函数一样调用，需要在类里面使用call方法，把类的实例变成可调用对象(callable)，也就是说可以像调用函数一样进行调用。在call方法里进行对fn函数的装饰，可以添加额外的功能。 执行结果:请先登陆…发表评论 mini-web框架web框架概述web框架和web服务器的关系介绍： 前面已经学习过web服务器, 我们知道web服务器主要是接收用户的http请求,根据用户的请求返回不同的资源数据，但是之前我们开发的是静态web服务器，返回的都是静态资源数据，假如我们想要web服务器返回动态资源那么该如何进行处理呢？ 使用web框架专门负责处理用户的动态资源请求，这个web框架其实就是一个为web服务器提供服务的应用程序，简称web框架。 关系说明: web服务器接收浏览器发起的请求，如果是动态资源请求找web框架来处理 web框架负责处理浏览器的动态资源请求，把处理的结果发生给web服务器 web服务器再把响应结果发生给浏览器 静态资源:不需要经常变化的资源，这种资源web服务器可以提前准备好，比如: png/jpg/css/js等文件。 动态资源:和静态资源相反, 这种资源会经常变化，比如: 我们在京东浏览商品时经常会根据条件进行筛选，选择不同条件, 浏览的商品就不同，这种资源web服务器无法提前准备好，需要web框架来帮web服务器进行准备，在这里web服务器可以把.html的资源请求认为是动态资源请求交由web框架进行处理。 WSGI协议:Web服务器网关接口(Python Web Server Gateway Interface，缩写为WSGI）是为Python语言定义的Web服务器和Web应用程序或框架之间的一种简单而通用的接口。自从WSGI被开发出来以后，许多其它语言中也出现了类似接口。它是web服务器和web框架之间进行协同工作的一个规则，WSGI协议规定web服务器把动态资源的请求信息传给web框架处理，web框架把处理好的结果返回给web服务器。 框架程序开发框架职责介绍 接收web服务器的动态资源请求，给web服务器提供处理动态资源请求的服务。动态资源判断根据请求资源路径的后缀名进行判断 如果请求资源路径的后缀名是.html则是动态资源请求, 让web框架程序进行处理。 否则是静态资源请求，让web服务器程序进行处理。 web服务器程序(web.py)代码:  socketimport threadingimport sysimport framework# 定义web服务器类class HttpWebServer(object): def __init__(self, port): # 创建tcp服务端套接字 tcp_server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM) # 设置端口号复用, 程序退出端口立即释放 tcp_server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, True) # 绑定端口号 tcp_server_socket.bind((&quot;&quot;, port)) # 设置监听 tcp_server_socket.listen(128) self.tcp_server_socket = tcp_server_socket # 处理客户的请求,申明静态方法 @staticmethod def handle_client_quest(new_socket): # 代码执行到此，说明连接建立成功 recv_client_data = new_socket.recv(4096) if len(recv_client_data) == 0: print(&quot;关闭浏览器了&quot;) # 关闭服务与客户端的套接字 new_socket.close() return # 对二进制数据进行解码 recv_client_content = recv_client_data.decode(&quot;utf-8&quot;) print(recv_client_content) # 根据指定字符串进行分割， 最大分割次数指定2 request_list = recv_client_content.split(&quot; &quot;, maxsplit=2) # 获取请求资源路径 request_path = request_list[1] print(request_path) # 判断请求的是否是根目录，如果条件成立，指定首页数据返回 if request_path == &quot;/&quot;: request_path = &quot;/index.html&quot; # 判断是否是动态资源请求 if request_path.endswith(&quot;.html&quot;): &quot;&quot;&quot;这里是动态资源请求，把请求信息交给框架处理&quot;&quot;&quot; # 字典存储用户的请求信息 env = { &quot;request_path&quot;: request_path } # 获取处理结果 status, headers, response_body = framework.handle_request(env) # 使用框架处理的数据拼接响应报文 # 响应行 response_line = &quot;HTTP/1.1 %s
&quot; % status # 响应头 response_header = &quot;&quot; # 遍历头部信息 for header in headers: # 拼接多个响应头 response_header += &quot;%s: %s
&quot; % header response_data = (response_line + response_header + &quot;
&quot; + response_body).encode(&quot;utf-8&quot;) # 发送数据 new_socket.send(response_data) # 关闭socket new_socket.close() else: &quot;&quot;&quot;这里是静态资源请求&quot;&quot;&quot; try: # 动态打开指定文件 with open(&quot;static&quot; + request_path, &quot;rb&quot;) as file: # 读取文件数据 file_data = file.read() except Exception as e: # 请求资源不存在，返回404数据 # 响应行 response_line = &quot;HTTP/1.1 404 Not Found
&quot; # 响应头 response_header = &quot;Server: PWS1.0
&quot; with open(&quot;static/error.html&quot;, &quot;rb&quot;) as file: file_data = file.read() # 响应体 response_body = file_data # 拼接响应报文 response_data = (response_line + response_header + &quot;
&quot;).encode(&quot;utf-8&quot;) + response_body # 发送数据 new_socket.send(response_data) else: # 响应行 response_line = &quot;HTTP/1.1 200 OK
&quot; # 响应头 response_header = &quot;Server: PWS1.0
&quot; # 响应体 response_body = file_data # 拼接响应报文 response_data = (response_line + response_header + &quot;
&quot;).encode(&quot;utf-8&quot;) + response_body # 发送数据 new_socket.send(response_data) finally: # 关闭服务与客户端的套接字 new_socket.close() def start(self): while True: # 等待接受客户端的连接请求 new_socket, ip_port = self.tcp_server_socket.accept() sub_thread = threading.Thread(target=self.handle_client_quest, args=(new_socket,)) # 设置守护线程 sub_thread.setDaemon(True) sub_thread.start()# 程序入口函数def main(): # 获取命令行参数判断长度 if len(sys.argv) != 2: print(&quot;执行命令如下: python3 xxx.py 9000&quot;) return # 判断端口号是否是数字 if not sys.argv[1].isdigit(): print(&quot;执行命令如下: python3 xxx.py 9000&quot;) return # 需要转成int类型 port = int(sys.argv[1]) # 创建web服务器 web_server = HttpWebServer(port) # 启动web服务器 web_server.start()if __name__ == '__main__': main() 处理客户端的动态资源请求 创建web框架程序 接收web服务器的动态资源请求 处理web服务器的动态资源请求并把处理结果返回给web服务器 web服务器把处理结果组装成响应报文发送给浏览器 web框架程序(framework.py)代码: 123456789101112131415161718192021222324252627282930313233343536373839404142&quot;&quot;&quot;miniweb框架，负责处理动态资源请求&quot;&quot;&quot;import time# 获取首页数据def index(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 处理后的数据 data = time.ctime() return status, response_header, data# 没有找到动态资源def not_found(): # 响应状态 status = &quot;404 Not Found&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 处理后的数据 data = &quot;not found&quot; return status, response_header, data# 处理动态资源请求def handle_request(env): # 获取动态请求资源路径 request_path = env[&quot;request_path&quot;] print(&quot;接收到的动态资源请求:&quot;, request_path) if request_path == &quot;/index.html&quot;: # 获取首页数据 result = index() return result else: # 没有找到动态资源 result = not_found() return result 模板替换功能开发,使用模拟数据替换模板变量framework.py示例代码: 1234567891011121314151617# 获取首页数据def index(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 1. 打开模板文件，读取数据 with open(&quot;template/index.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 处理后的数据, 从数据库查询 data = time.ctime() # 2. 替换模板文件中的模板遍历 result = file_data.replace(&quot;{%content%}&quot;, data) return status, response_header, result 路由列表功能开发 什么是路由？路由就是请求的URL到处理函数的映射，也就是说提前把请求的URL和处理函数关联好。 路由列表:这么多的路由如何管理呢， 可以使用一个路由列表进行管理，通过路由列表保存每一个路由。 在路由列表添加路由,根据用户请求遍历路由列表处理用户请求1234567891011121314151617181920# 定义路由列表route_list = [ (&quot;/index.html&quot;, index), (&quot;/center.html&quot;, center)]# 处理动态资源请求def handle_request(env): # 获取动态请求资源路径 request_path = env[&quot;request_path&quot;] print(&quot;接收到的动态资源请求:&quot;, request_path) # 遍历路由列表，选择执行的函数 for path, func in route_list: if request_path == path: result = func() return result else: # 没有找到动态资源 result = not_found() return result 装饰器方式的添加路由前面我们已经实现了路由列表，但是每次添加路由都需要手动添加来完成，接下来我们想要完成路由的自动添加，可以通过装饰器来实现，在使用装饰器对处理函数进行装饰的时候我们需要知道装饰的函数和那个请求路径进行关联，也就是说装饰器需要接收一个url参数，这样我们定义的装饰器是一个带有参数的装饰器。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990&quot;&quot;&quot;miniweb框架，负责处理动态资源请求&quot;&quot;&quot;import time# 定义路由列表route_list = []# 定义带有参数的装饰器def route(path): # 装饰器 def decorator(func): # 当执行装饰器装饰指定函数的时候，把路径和函数添加到路由列表 route_list.append((path, func)) def inner(): # 执行指定函数 return func() return inner # 返回装饰器 return decorator# 获取首页数据@route(&quot;/index.html&quot;)def index(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 打开模板文件，读取数据 with open(&quot;template/index.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 处理后的数据, 从数据库查询 data = time.ctime() # 替换模板文件中的模板遍历 result = file_data.replace(&quot;{%content%}&quot;, data) return status, response_header, result# 获取个人中心数据@route(&quot;/center.html&quot;)def center(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 打开模板文件，读取数据 with open(&quot;template/center.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 处理后的数据, 从数据库查询 data = time.ctime() # 替换模板文件中的模板遍历 result = file_data.replace(&quot;{%content%}&quot;, data) return status, response_header, result# 没有找到动态资源def not_found(): # 响应状态 status = &quot;404 Not Found&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 处理后的数据 data = &quot;not found&quot; return status, response_header, data# 处理动态资源请求def handle_request(env): # 获取动态请求资源路径 request_path = env[&quot;request_path&quot;] print(&quot;接收到的动态资源请求:&quot;, request_path) # 遍历路由列表，选择执行的函数 for path, func in route_list: if request_path == path: result = func() return result else: # 没有找到动态资源 result = not_found() return result 显示股票信息页面的开发数据准备123456-- 创建数据库create database stock_db charset=utf8;-- 切换数据库use stock_db;-- 执行sql文件source stock_db.sql; 根据sql语句查询股票信息123456789101112131415161718192021222324252627282930# 获取首页数据@route(&quot;/index.html&quot;)def index(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 打开模板文件，读取数据 with open(&quot;template/index.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 处理后的数据, 从数据库查询 conn = pymysql.connect(host=&quot;localhost&quot;, port=3306, user=&quot;root&quot;, password=&quot;mysql&quot;, database=&quot;stock_db&quot;, charset=&quot;utf8&quot;) # 获取游标 cursor = conn.cursor() # 查询sql语句 sql = &quot;select * from info;&quot; # 执行sql cursor.execute(sql) # 获取结果集 result = cursor.fetchall() print(result) 使用查询数据替换模板变量123456789101112131415161718192021222324252627282930313233343536373839404142434445464748# 获取首页数据@route(&quot;/index.html&quot;)def index(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 打开模板文件，读取数据 with open(&quot;template/index.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 处理后的数据, 从数据库查询 conn = pymysql.connect(host=&quot;localhost&quot;, port=3306, user=&quot;root&quot;, password=&quot;mysql&quot;, database=&quot;stock_db&quot;, charset=&quot;utf8&quot;) # 获取游标 cursor = conn.cursor() # 查询sql语句 sql = &quot;select * from info;&quot; # 执行sql cursor.execute(sql) # 获取结果集 result = cursor.fetchall() print(result) data = &quot;&quot; for row in result: data += '''&lt;tr&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;%s&lt;/td&gt; &lt;td&gt;&lt;input type=&quot;button&quot; value=&quot;添加&quot; id=&quot;toAdd&quot; name=&quot;toAdd&quot; systemidvaule=&quot;000007&quot;&gt;&lt;/td&gt; &lt;/tr&gt;''' % row # 替换模板文件中的模板遍历 result = file_data.replace(&quot;{%content%}&quot;, data) return status, response_header, result 个人中心数据接口的开发根据sql语句查询个人中心数据.将个人中心数据转成json字符串并返回12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849# 个人中心数据接口开发@route(&quot;/center_data.html&quot;)def center_data(): # 响应状态 status = &quot;200 OK&quot;; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;), (&quot;Content-Type&quot;, &quot;text/html;charset=utf-8&quot;)] conn = pymysql.connect(host=&quot;localhost&quot;, port=3306, user=&quot;root&quot;, password=&quot;mysql&quot;, database=&quot;stock_db&quot;, charset=&quot;utf8&quot;) # 获取游标 cursor = conn.cursor() # 查询sql语句 sql = '''select i.code, i.short, i.chg, i.turnover, i.price, i.highs, f.note_info from info as i inner join focus as f on i.id = f.info_id;''' # 执行sql cursor.execute(sql) # 获取结果集 result = cursor.fetchall() # 关闭游标 cursor.close() # 关闭数据库连接 conn.close() print(result) # 个人中心数据列表 center_data_list = list() # 遍历每一行数据转成字典 for row in result: # 创建空的字典 center_dict = dict() center_dict[&quot;code&quot;] = row[0] center_dict[&quot;short&quot;] = row[1] center_dict[&quot;chg&quot;] = row[2] center_dict[&quot;turnover&quot;] = row[3] center_dict[&quot;price&quot;] = str(row[4]) center_dict[&quot;highs&quot;] = str(row[5]) center_dict[&quot;note_info&quot;] = row[6] # 添加每个字典信息 center_data_list.append(center_dict) # 把列表字典转成json字符串, 并在控制台显示 json_str = json.dumps(center_data_list,ensure_ascii=False) print(json_str) return status, response_header, json_str 代码说明: json.dumps函数把字典转成json字符串:函数的第一个参数表示要把指定对象转成json字符串,参数的第二个参数ensure_ascii=False表示不使用ascii编码，可以在控制台显示中文。 响应头添加Content-Type表示指定数据的编码格式 ajax请求数据渲染个人中心页面12345678910111213141516# 获取个人中心数据@route(&quot;/center.html&quot;)def center(): # 响应状态 status = &quot;200 OK&quot; # 响应头 response_header = [(&quot;Server&quot;, &quot;PWS2.0&quot;)] # 打开模板文件，读取数据 with open(&quot;template/center.html&quot;, &quot;r&quot;) as file: file_data = file.read() # 替换模板文件中的模板遍历 result = file_data.replace(&quot;{%content%}&quot;, &quot;&quot;) return status, response_header, result 根据用户请求返回个人中心空模板文件数据,在个人中心模板文件添加ajax请求获取个人中心数据 123456789101112131415161718192021222324// 发送ajax请求获取个人中心页面数据$.get(&quot;center_data.html&quot;, function (data) { var data_array = data; // 获取table标签对象 var $table = $(&quot;.table&quot;) for(var i = 0; i &lt; data_array.length; i++){ // 获取每一条对象 var center_obj = data_array[i]; var row_html = '&lt;tr&gt;' + '&lt;td&gt;'+ center_obj.code +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.short +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.chg +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.turnover +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.price +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.highs +'&lt;/td&gt;' + '&lt;td&gt;'+ center_obj.note_info +'&lt;/td&gt;' + '&lt;td&gt;&lt;a type=&quot;button&quot; class=&quot;btn btn-default btn-xs&quot; href=&quot;/update/000007.html&quot;&gt; &lt;span class=&quot;glyphicon glyphicon-star&quot; aria-hidden=&quot;true&quot;&gt;&lt;/span&gt; 修改 &lt;/a&gt;&lt;/td&gt;&lt;td&gt;&lt;input type=&quot;button&quot; value=&quot;删除&quot; id=&quot;toDel&quot; name=&quot;toDel&quot; systemidvaule=&quot;000007&quot;&gt;&lt;/td&gt;&lt;/tr&gt;'; // 为table标签添加每一行组装的html数据 $table.append(row_html); }}, &quot;json&quot;); logging日志logging日志的介绍在现实生活中，记录日志非常重要，比如:银行转账时会有转账记录；飞机飞行过程中，会有个黑盒子（飞行数据记录器）记录着飞机的飞行过程，那在咱们python程序中想要记录程序在运行时所产生的日志信息，怎么做呢?可以使用 logging 这个包来完成记录程序日志信息的目的是: 可以很方便的了解程序的运行情况 可以分析用户的操作行为、喜好等信息 方便开发人员检查bug==logging日志级别介绍==日志等级可以分为5个，从低到高分别是:DEBUG,INFO,WARNING,ERROR,CRITICAL日志等级说明: DEBUG：程序调试bug时使用 INFO：程序正常运行时使用 WARNING：程序未按预期运行时使用，但并不是错误，如:用户登录密码错误 ERROR：程序出错误时使用，如:IO操作失败 CRITICAL：特别严重的问题，导致程序不能再继续运行时使用，如:磁盘空间为空，一般很少使用默认的是WARNING等级，当在WARNING或WARNING之上等级的才记录日志信息。日志等级从低到高的顺序是: DEBUG &lt; INFO &lt; WARNING &lt; ERROR &lt; CRITICALlogging日志的使用在 logging 包中记录日志的方式有两种: 输出到控制台 保存到日志文件日志信息输出到控制台的示例代码:1234567import logginglogging.debug('这是一个debug级别的日志信息')logging.info('这是一个info级别的日志信息')logging.warning('这是一个warning级别的日志信息')logging.error('这是一个error级别的日志信息')logging.critical('这是一个critical级别的日志信息') 日志信息只显示了大于等于WARNING级别的日志，这说明·默认的日志级别设置为WARNING·logging日志等级和输出格式的设置:1234567891011import logging# 设置日志等级和输出日志格式logging.basicConfig(level=logging.DEBUG, format='%(asctime)s - %(filename)s[line:%(lineno)d] - %(levelname)s: %(message)s')logging.debug('这是一个debug级别的日志信息')logging.info('这是一个info级别的日志信息')logging.warning('这是一个warning级别的日志信息')logging.error('这是一个error级别的日志信息')logging.critical('这是一个critical级别的日志信息') level 表示设置的日志等级 format 表示日志的输出格式, 参数说明: %(levelname)s: 打印日志级别名称 %(filename)s: 打印当前执行程序名 %(lineno)d: 打印日志的当前行号 %(asctime)s: 打印日志的时间 %(message)s: 打印日志信息日志信息保存到日志文件的示例代码: 123456789101112import logginglogging.basicConfig(level=logging.DEBUG, format='%(asctime)s - %(filename)s[line:%(lineno)d] - %(levelname)s: %(message)s', filename=&quot;log.txt&quot;, filemode=&quot;w&quot;)logging.debug('这是一个debug级别的日志信息')logging.info('这是一个info级别的日志信息')logging.warning('这是一个warning级别的日志信息')logging.error('这是一个error级别的日志信息')logging.critical('这是一个critical级别的日志信息') logging日志在mini-web项目中应用web.py 程序使用logging日志示例:1.程序入口模块设置logging日志的设置 1234567891011import socket import threading import sys import framework import logging # logging日志的配置 logging.basicConfig(level=logging.DEBUG, format='%(asctime)s - %(filename)s[line:%(lineno)d] - %(levelname)s: %(message)s', filename=&quot;log.txt&quot;, filemode=&quot;w&quot;) 2.INFO级别的日志输出，示例代码: 123456789# 判断是否是动态资源请求 if request_path.endswith(&quot;.html&quot;): &quot;&quot;&quot;这里是动态资源请求，把请求信息交给框架处理&quot;&quot;&quot; logging.info(&quot;动态资源请求:&quot; + request_path) ... else: &quot;&quot;&quot;这里是静态资源请求&quot;&quot;&quot; logging.info(&quot;静态资源请求:&quot; + request_path) ... 3.WARNING级别的日志输出，示例代码: 1234567891011# 获取命令行参数判断长度 if len(sys.argv) != 2: print(&quot;执行命令如下: python3 xxx.py 9000&quot;) logging.warning(&quot;用户在命令行启动程序参数个数不正确!&quot;) return # 判断端口号是否是数字 if not sys.argv[1].isdigit(): print(&quot;执行命令如下: python3 xxx.py 9000&quot;) logging.warning(&quot;用户在命令行启动程序参数不是数字字符串!&quot;) return framework.py 程序使用logging日志示例:4.ERROR级别的日志输出，示例代码: 123456789101112131415# 处理动态资源请求def handle_request(env): # 获取动态请求资源路径 request_path = env[&quot;request_path&quot;] print(&quot;接收到的动态资源请求:&quot;, request_path) # 遍历路由列表，选择执行的函数 for path, func in route_list: if request_path == path: result = func() return result else: logging.error(&quot;没有设置相应的路由:&quot; + request_path) # 没有找到动态资源 result = not_found() return result ==logging日志配置信息在程序入口模块设置一次，整个程序都可以生效==。logging.basicConfig 表示 logging 日志配置操作

想念想念，一经想起便念念不忘了。——烽火戏诸侯 《雪中悍刀行》 写在前面 有一个系统中不知道什么原因，Redis有个K要定期清理，但是没有权限在服务器上搞，而且服务器也没有redis的客户端 所以只能本地写一个python脚本，然后配置一个定时任务. 逻辑很简单,但是要考虑集群的问题 想念想念，一经想起便念念不忘了。——烽火戏诸侯 《雪中悍刀行》 嗯，实现很简单，连接Redis之后，直接处理就可以了，这里要注意的是集群的问题，redis连接成功，报错 1234D:\haojingkeji lask-vue-crudedisclear&gt;python redisclear.pyredis连接成功 Redis&lt;ConnectionPool&lt;Connection&lt;host=192.168.50.162,port=8003,db=0&gt;&gt;&gt;MOVED 15160 192.168.50.177:8003 redis可以连接成功，但是你要处理的键不在你连接的节点上，那么这时候redis 会告诉你键所在的节点即：MOVED 15160 192.168.50.177:8003 我们用Node ID来标识集群中的节点， 但是为了让客户端的转向操作尽可能地简单， 节点在 MOVED 错误中直接返回目标节点的 IP 和端口号， 。我们客户端记录槽15495由节点 192.168.50.177:8003负责处理，然后通过这一信息处理键数据 可以用返回的MOVED 错误里的IP和端口连接就可以了，即客户端可以直接向正确的节点发送命令请求，或者也可以捕获异常的方式处理。我们这里用了第二种 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950#!/usr/bin/env python# -*- encoding: utf-8 -*-# pip install redis# Python 3.9.0'''@File : redisclear.py@Time : 2021/12/1 10:32:56@Author : Li Ruilong@Version : 1.0@Contact : 1224965096@qq.com@Desc : redis key-value --&gt; clear'''# here put the import libimport redisimport timeip = '192.168.26.26'password = '************'port = 8333conn=redis.Redis(host=ip,password=password,port=port,decode_responses=True)print(&quot;redis conntion succeed &quot;,conn,&quot;
&quot;)def ex(conn): time.sleep(3) print(&quot;old key=&quot;,conn.get('GROUP_CIRCUIT-3'),&quot;
&quot;) conn.set('GROUP_CIRCUIT-3',600) time.sleep(3) print(&quot;new key=&quot;,conn.get('GROUP_CIRCUIT-3'),&quot;
&quot;)if __name__ == '__main__': try: rs = conn.get('GROUP_CIRCUIT-3') except Exception as e: print(e) c= str(e).split() ip = str(c[2]).split(':')[0] port = str(c[2]).split(':')[1] print(ip,port,&quot;
&quot;) conn=redis.Redis(host=ip,password=password,port=int(port),decode_responses=True) rs = conn.get('GROUP_CIRCUIT-3') ex(conn) else: ex(conn)
